// true si se abre desde file:// (doble click en el archivo)
const __IS_LOCAL = location.protocol === 'file:';

function setLoad(msg, pct){
  const m=document.getElementById('loadMsg');
  const b=document.getElementById('loadBar');
  if(m) m.textContent=msg;
  if(b) b.style.width=pct+'%';
}

async function loadData(){
  // Si hay datos inline (modo offline o fallback) y estamos en local → usar inline
  if(__DATA_INLINE !== null && __IS_LOCAL){
    setLoad('Cargando datos locales…', 80);
    return __DATA_INLINE;
  }

  // Modo remoto: fetch desde GitHub Pages (o cualquier servidor HTTP)
  if(__MODO_REMOTO && __DATA_URL){
    setLoad('Descargando datos…', 30);
    try{
      const r = await fetch(__DATA_URL + '?t=' + Date.now());
      if(!r.ok) throw new Error('HTTP ' + r.status);
      setLoad('Procesando JSON…', 70);
      return await r.json();
    } catch(e){
      // Fallback a inline si existe
      if(__DATA_INLINE !== null){
        setLoad('Usando datos locales…', 75);
        return __DATA_INLINE;
      }
      setLoad('Error al cargar datos: ' + e.message, 100);
      throw e;
    }
  }

  // Modo inline puro
  if(__DATA_INLINE !== null){
    setLoad('Datos listos', 80);
    return __DATA_INLINE;
  }

  throw new Error('No hay datos disponibles. Ejecuta procesar_datos.py primero.');
}


const CFG_KEY      = 'sk_tipo_map';
const CFG_UI_KEY   = 'sk_ui_cfg';   // configuración visual

const TIPO_MAP_DEFAULT = {
  'Credito Bancolombia 365 $':'CDT',
};

// Configuración UI por defecto
const UI_CFG_DEFAULT = {
  theme:        'light',      // dark | light
  accentColor:  '#00854A',    // color principal
  compactKpis:  false,        // KPIs compactos
  showNominal:  true,         // mostrar nominal en gráficas
  tabDefault:   'general',    // tab por defecto al abrir
  decimalPct:   2,            // decimales en porcentajes
  chartAnim:    true,         // animaciones en gráficas
  kpiRows:      2,            // filas de KPIs (1 o 2)
  insightsPos:  'top',        // top | bottom
  tablePageSize: 50,          // filas por página en tabla detalle
  exportFormat: 'csv',        // csv | xlsx
};

function loadCfg(){
  try{ return JSON.parse(localStorage.getItem(CFG_KEY))||TIPO_MAP_DEFAULT; }
  catch{ return TIPO_MAP_DEFAULT; }
}
function saveCfg(obj){ localStorage.setItem(CFG_KEY, JSON.stringify(obj)); }
let TIPO_MAP = loadCfg();

function loadUICfg(){
  try{ return {...UI_CFG_DEFAULT,...JSON.parse(localStorage.getItem(CFG_UI_KEY))||{}}; }
  catch{ return {...UI_CFG_DEFAULT}; }
}
function saveUICfg(obj){ localStorage.setItem(CFG_UI_KEY, JSON.stringify(obj)); }
let UI_CFG = loadUICfg();

function applyTipoMap(rows){
  // TIPO_MAP viene del tab "Tipos de activo" + overrides del tab "Mapas"
  const ov = loadMapasOverride();
  const combined = {...TIPO_MAP, ...(ov.tipo_map||{})};
  return rows.map(r=>{
    const override = combined[r.esp];
    return override ? {...r, tipo: override} : r;
  });
}

// Devuelve el nombre legible de un portafolio usando los mapas del usuario
function portNom(cod){
  const m = getMapas();
  return m.ports[cod] || cod || '—';
}
// Devuelve nombre de moneda usando los mapas del usuario
function monNom(cod){
  const m = getMapas();
  return m.monedas[cod] || cod || '—';
}


