// helper: crea un gradiente vertical para línea/área
function grad(ctx, top, bot, alpha1=0.25, alpha2=0){
  const g=ctx.createLinearGradient(0,0,0,ctx.canvas.offsetHeight||300);
  g.addColorStop(0, top.replace(')',`,${alpha1})`).replace('rgb','rgba'));
  g.addColorStop(1, bot.replace(')',`,${alpha2})`).replace('rgb','rgba'));
  return g;
}
// helper: hex → rgb string
function h2r(hex){
  const r=parseInt(hex.slice(1,3),16),g=parseInt(hex.slice(3,5),16),b=parseInt(hex.slice(5,7),16);
  return `rgb(${r},${g},${b})`;
}

// ─── KPI HTML ─────────────────────────────────────────────────
// Iconos SVG para KPIs — claves normalizadas sin caracteres especiales
// (las claves con &, tildes, etc. causaban error de parseo en HTML)
const KPI_ICONS_SVG = [
  'M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5',
  'M22 12h-4l-3 9L9 3l-3 9H2',
  'M12 20V10 M18 20V4 M6 20v-4',
  'M12 2a10 10 0 110 20A10 10 0 0112 2zM12 6v6l4 2',
  'M22 7l-8.5 8.5-5-5L2 17 M16 7h6v6',
  'M2 3h20v14H2z M8 21h8 M12 17v4',
  'M18 20V10 M12 20V4 M6 20v-6',
  'M12 1v22 M17 5H9.5a3.5 3.5 0 000 7h5a3.5 3.5 0 010 7H6',
  'M2.5 2v6h6M2.66 15.57a10 10 0 100 .86',
  'M12 2a10 10 0 110 20 M2 12h20',
];

function kH(label,val,delta,signN,color,sub){
  const dc=delta!=null?`<div class="kd ${signN>0?'pos':signN<0?'neg':'neu'}">${signN>0?'+':signN<0?'-':'~'} ${delta}</div>`:'';
  const vc=signN!=null?(signN>0?'pos':signN<0?'neg':''):'';
  // Seleccionar icono por hash simple del label
  const icoIdx=label.split('').reduce((a,c)=>a+c.charCodeAt(0),0)%KPI_ICONS_SVG.length;
  const icoPath=KPI_ICONS_SVG[icoIdx];
  return`<div class="kpi">
    <div class="ka" style="background:linear-gradient(180deg,${color},${color}88)"></div>
    <div class="kpi-bg" style="background:${color}"></div>
    <div class="kl">
      <svg viewBox="0 0 24 24" style="stroke:${color};fill:none;stroke-width:2;stroke-linecap:round;stroke-linejoin:round"><path d="${icoPath}"/></svg>
      ${label}
    </div>
    <div class="kv ${vc}">${val}</div>
    ${dc}<div class="ks">${sub||''}</div>
  </div>`;
}

