// Calcula KPIs base del último día filtrado
function calcKPIs(){
  const rows=FD(), ev=FE();
  const total  = rows.reduce((a,r)=>a+(r.valor||0),0);
  const ant    = rows.reduce((a,r)=>a+(r.v_ant||0),0);
  const pl     = rows.reduce((a,r)=>a+(r.pl||0),0);
  const cmer   = rows.reduce((a,r)=>a+(r.caus_mer||0),0);
  const ctir   = rows.reduce((a,r)=>a+(r.caus_tir||0),0);
  const cmon   = rows.reduce((a,r)=>a+(r.caus_mon||0),0);
  const ctasa  = rows.reduce((a,r)=>a+(r.caus_tasa||0),0);
  const adeud  = rows.reduce((a,r)=>a+(r.adeudados||0),0);
  const varP   = ant?pl/ant*100:0;
  const plAcum = ev.pl_acum[ev.pl_acum.length-1]||0;
  const mt     = rows.filter(r=>r.tir&&r.tir>0.0001&&r.tir<30);
  const tirP   = mt.length?mt.reduce((a,r)=>a+r.tir*(r.valor||0),0)/mt.reduce((a,r)=>a+(r.valor||0),0):null;
  const fxTotal= rows.filter(r=>r.ext).reduce((a,r)=>a+(r.valor||0),0);
  const rf     = rows.filter(r=>['TES','TIDIS','CDT','Titularizaciones'].includes(r.tipo));
  const rfVal  = rf.reduce((a,r)=>a+(r.valor||0),0);
  const rd     = rf.filter(r=>r.dias_vcto>0);
  const durP   = rd.length?rd.reduce((a,r)=>a+r.dias_vcto*(r.valor||0),0)/rd.reduce((a,r)=>a+(r.valor||0),0):null;
  return {rows,ev,total,ant,pl,cmer,ctir,cmon,ctasa,adeud,varP,plAcum,tirP,fxTotal,rf,rfVal,durP};
}

// Construye las portfolio cards (reutilizado en Resumen)
function buildPortCards(rows,ttl){
  const byP={};
  rows.forEach(r=>{
    if(!byP[r.port])byP[r.port]={total:0,pl:0,caus:0,n:0};
    const b=byP[r.port];
    b.total+=(r.valor||0);b.pl+=(r.pl||0);b.caus+=(r.caus_mer||0);b.n++;
  });
  const portArr=Object.entries(byP).sort((a,b)=>b[1].total-a[1].total);
  const maxPct=portArr[0]&&ttl?portArr[0][1].total/ttl*100:100;
  return portArr.map(function([p,b],i){
    const col=PC[i%PC.length];
    const pct=ttl?b.total/ttl*100:0;
    const ep=D.evol_port[p];
    const fi=D.fechas.indexOf(S.f.desde), li=D.fechas.indexOf(S.f.hasta);
    const v0=fi>=0&&ep?(ep.total[fi]||0):0;
    const v1=li>=0&&ep?(ep.total[li]||0):0;
    const delta=v0?(v1-v0)/v0*100:0;
    // Evitar ternarios con var(--x) dentro de template literals — rompen el parser HTML
    const plCls = b.pl>=0 ? 'pos' : 'neg';
    const dltCls = delta>=0 ? 'green' : 'red';
    const dltStyle = delta>=0 ? 'color:var(--g)' : 'color:var(--r)';
    const progW = maxPct>0 ? (pct/maxPct*100).toFixed(1) : '0';
    let html = '<div class="pcard">';
    html += '<div class="pcard-accent" style="background:linear-gradient(90deg,'+col+','+col+'55)"></div>';
    html += '<div class="pc-name"><span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:'+col+';flex-shrink:0;margin-right:5px"></span>'+p+'</div>';
    html += '<div class="pc-val">'+fC(b.total)+'</div>';
    html += '<div class="pc-pl '+plCls+'">'+sgn(b.pl)+fC(b.pl)+'</div>';
    html += '<div class="pc-prog-wrap">';
    html += '<div class="pc-prog-label"><span>% del total</span><span style="color:'+col+';font-weight:700">'+fP(pct)+'</span></div>';
    html += '<div class="pc-prog"><div class="pc-prog-fill" style="width:'+progW+'%;background:'+col+'"></div></div>';
    html += '</div>';
    html += '<div class="pc-sep"></div>';
    html += '<div class="pc-row"><span>Causación mer.</span><span>'+fC(b.caus)+'</span></div>';
    html += '<div class="pc-row"><span>Posiciones</span><span>'+b.n+'</span></div>';
    html += '<div class="pc-row"><span>Var. período</span><span style="'+dltStyle+';font-weight:700">'+sgn(delta)+fP(delta)+'</span></div>';
    html += '</div>';
    return html;
  }).join('');
}

