function initResumen(){
  const {rows,ev,total,ant,pl,cmer,ctir,cmon,ctasa,varP,plAcum,tirP,fxTotal,durP}=calcKPIs();

  document.getElementById('kpiA').innerHTML=
    kH('Valor de Mercado',fC(total),null,null,'#00854A','Total portafolio filtrado')+
    kH('P&L del Día',fC(pl),sgn(pl)+fP(varP),pl,'#00854A','vs. día anterior')+
    kH('P&L Acumulado',fC(plAcum),null,plAcum,'#8b5cf6','Período seleccionado')+
    kH('TIR Ponderada',tirP?fP(tirP*100):'—',null,null,'#f59e0b','RF ponderada por valor')+
    kH('Causación Mercado',fC(cmer),null,cmer,'#3b82f6','Devengado a precios de mercado');

  document.getElementById('kpiB').innerHTML=
    kH('Posiciones',String(rows.length),null,null,'#06b6d4','Instrumentos activos')+
    kH('Causación TIR',fC(ctir),null,ctir,'#3b82f6','Devengado a TIR de compra')+
    kH('Causación FX',fC(cmon),null,cmon,'#f97316','Efecto tipo de cambio')+
    kH('Causación Tasa',fC(ctasa),null,ctasa,'#8b5cf6','Efecto tasas de interés')+
    kH('Exp. FX',fC(fxTotal),null,null,'#f97316','En moneda extranjera');

  document.getElementById('portCards').innerHTML = buildPortCards(rows, total);

  const lbs=dateL(ev.fechas);
  mkC('cGA',{type:'line',data:{labels:lbs,datasets:[{
    label:'Valor Mercado',data:ev.total,borderColor:'#00854A',
    backgroundColor:(ctx)=>{const g=ctx.chart.ctx.createLinearGradient(0,0,0,ctx.chart.height||220);g.addColorStop(0,'rgba(0,133,74,.25)');g.addColorStop(1,'rgba(0,133,74,0)');return g;},
    fill:true,tension:.4,pointRadius:0,pointHoverRadius:5,borderWidth:2.5
  }]},options:{...CHART_DEFAULTS,plugins:{legend:{display:false},tooltip:{...tipFull(),mode:'index',intersect:false}},scales:axO()}});

  mkC('cGB',{type:'bar',data:{labels:lbs,datasets:[
    {label:'P&L Diario',data:ev.pl,yAxisID:'y',
      backgroundColor:ev.pl.map(v=>v>=0?'rgba(0,200,110,.75)':'rgba(239,68,68,.75)'),borderRadius:4,borderSkipped:false,barPercentage:.75},
    {label:'P&L Acumulado',data:ev.pl_acum,yAxisID:'y2',type:'line',
      borderColor:'#a78bfa',backgroundColor:'transparent',tension:.4,pointRadius:0,borderWidth:2.5}
  ]},options:{...CHART_DEFAULTS,
    onClick:(e,els)=>{ if(els.length) _showDiaAtipicoPanel(ev.fechas[els[0].index], ev.pl[els[0].index], ev); },
    plugins:{legend:leg('top'),tooltip:tipBI()},
    scales:{x:{ticks:{color:tx2(),font:{size:10.5}},grid:{color:gc(),drawBorder:false}},
      y:{ticks:{color:tx2(),font:{size:10.5},callback:v=>fmt(v)},grid:{color:gc(),drawBorder:false}},
      y2:{position:'right',ticks:{color:'rgba(167,139,250,.7)',font:{size:10.5},callback:v=>fmt(v)},grid:{display:false}}}}});

  // Rentabilidades EA
  _buildEATable(ev);
}

function _showDiaAtipicoPanel(fecha, plDia, ev){
  const panel=document.getElementById('atipicoPanel');
  if(!panel) return;
  // Encontrar top contribuyentes de ese día
  const fi=D.fechas.indexOf(fecha);
  if(fi<0){ panel.style.display='none'; return; }
  // Buscar en cada especie cuánto aportó ese día
  const contribs=[];
  Object.entries(D.esp_hist).forEach(([esp,h])=>{
    const idx=h.fechas.indexOf(fecha);
    if(idx<0) return;
    const pl=h.pl?.[idx]||0;
    if(Math.abs(pl)>0) contribs.push({esp,pl,tipo:h.tipo||'—',port:h.port||'—'});
  });
  contribs.sort((a,b)=>Math.abs(b.pl)-Math.abs(a.pl));
  const top=contribs.slice(0,8);

  // Calcular stats del día vs promedio
  const pl=ev.pl.filter(v=>v!=null);
  const avg=pl.reduce((a,v)=>a+v,0)/pl.length;
  const std=Math.sqrt(pl.reduce((a,v)=>a+Math.pow(v-avg,2),0)/(pl.length-1));
  const zscore=std>0?(plDia-avg)/std:0;
  const pctRank=pl.filter(v=>v<plDia).length/pl.length*100;

  const isGood=plDia>=0;
  const col=isGood?'var(--g)':'var(--r)';
  const zLabel=Math.abs(zscore)>2?'⚠️ Día muy atípico':Math.abs(zscore)>1?'Día inusual':'Día normal';

  let html=`<div style="display:flex;align-items:center;gap:16px;flex-wrap:wrap;margin-bottom:12px">
    <div>
      <div style="font-size:11px;color:var(--tx2);margin-bottom:2px">📅 ${fecha}</div>
      <div style="font-size:20px;font-weight:800;color:${col};font-family:var(--mono)">${sgn(plDia)+fC(plDia)}</div>
    </div>
    <div style="display:flex;gap:10px;flex-wrap:wrap">
      <div style="padding:6px 12px;background:var(--s1);border-radius:8px;border:1px solid var(--bd);font-size:11px">
        <div style="color:var(--tx2)">Z-score</div>
        <div style="font-weight:700;font-family:var(--mono);color:${Math.abs(zscore)>2?'var(--r)':'var(--tx)'}">${zscore.toFixed(2)}σ — ${zLabel}</div>
      </div>
      <div style="padding:6px 12px;background:var(--s1);border-radius:8px;border:1px solid var(--bd);font-size:11px">
        <div style="color:var(--tx2)">Percentil</div>
        <div style="font-weight:700;font-family:var(--mono)">${pctRank.toFixed(0)}° de ${pl.length} días</div>
      </div>
      <div style="padding:6px 12px;background:var(--s1);border-radius:8px;border:1px solid var(--bd);font-size:11px">
        <div style="color:var(--tx2)">vs Promedio</div>
        <div style="font-weight:700;font-family:var(--mono);color:${(plDia-avg)>=0?'var(--g)':'var(--r)'}">${sgn(plDia-avg)+fC(plDia-avg)}</div>
      </div>
    </div>
    <button onclick="document.getElementById('atipicoPanel').style.display='none'" style="margin-left:auto;padding:4px 10px;border-radius:6px;font-size:12px;border:1px solid var(--bd);color:var(--tx2);background:var(--s1);cursor:pointer">✕</button>
  </div>`;

  if(top.length){
    html+=`<div style="font-size:11px;font-weight:700;color:var(--tx2);text-transform:uppercase;letter-spacing:.6px;margin-bottom:8px">Top contribuyentes al P&L del día</div>`;
    html+=`<div style="display:flex;flex-direction:column;gap:4px">`;
    top.forEach(c=>{
      const pct=plDia?c.pl/Math.abs(plDia)*100:0;
      const barW=Math.min(Math.abs(pct),100);
      const barCol=c.pl>=0?'var(--g)':'var(--r)';
      html+=`<div style="display:flex;align-items:center;gap:10px;padding:6px 10px;background:var(--s1);border-radius:7px;border:1px solid var(--bd)">
        <div style="flex:1;min-width:0">
          <div style="font-size:11.5px;font-weight:600;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${escAttr(c.esp)}">${c.esp.length>32?c.esp.slice(0,32)+'…':escHtml(c.esp)}</div>
          <div style="font-size:10px;color:var(--tx2)">${escHtml(c.port)} · ${escHtml(c.tipo)}</div>
        </div>
        <div style="width:80px;height:5px;background:var(--s3);border-radius:3px;overflow:hidden;flex-shrink:0">
          <div style="height:100%;width:${barW}%;background:${barCol};border-radius:3px"></div>
        </div>
        <div style="font-family:var(--mono);font-size:11.5px;font-weight:700;color:${barCol};width:90px;text-align:right;flex-shrink:0">${sgn(c.pl)+fC(c.pl)}</div>
        <div style="font-size:10.5px;color:var(--tx2);width:45px;text-align:right;flex-shrink:0">${pct.toFixed(1)}%</div>
      </div>`;
    });
    html+=`</div>`;
  } else {
    html+=`<div style="font-size:12px;color:var(--tx2)">No hay detalle por especie disponible para este día.</div>`;
  }

  panel.innerHTML=html;
  panel.style.display='block';
}

function _buildEATable(ev){
  const cont=document.getElementById('eaTable');
  const lbl=document.getElementById('eaPeriodo');
  if(!cont) return;

  // Calcular EA = (1 + rendimiento_total)^(252/días) - 1
  // Para cada portafolio y para el total
  const fechas=ev.fechas;
  const dias=fechas.length;
  if(!dias){ cont.innerHTML='<div style="padding:16px;color:var(--tx2)">Sin datos en el período.</div>'; return; }

  if(lbl) lbl.textContent=`${fechas[0]} → ${fechas[fechas.length-1]} · ${dias} días hábiles`;

  const calcEA=(plArr,totalArr)=>{
    const plAcum=plArr.reduce((a,v)=>a+(v||0),0);
    const v0=totalArr.find(v=>v&&v>0)||0;
    const vN=totalArr[totalArr.length-1]||0;
    if(!v0||!vN) return null;
    const rendTotal=plAcum/v0;
    return Math.pow(1+rendTotal, 252/dias)-1;
  };

  // Portafolios disponibles
  const ports=S.f.port?[S.f.port]:D.ports;
  const rows=[];

  // Total
  const eaTotal=calcEA(ev.pl,ev.total);
  rows.push({label:'TOTAL', ea:eaTotal, plAcum:ev.pl.reduce((a,v)=>a+(v||0),0), isTotal:true});

  // Por portafolio
  ports.forEach(p=>{
    const ep=D.evol_port[p]; if(!ep) return;
    const plArr=fechas.map(f=>{const gi=D.fechas.indexOf(f);return gi>=0?(ep.pl[gi]||0):0;});
    const totArr=fechas.map(f=>{const gi=D.fechas.indexOf(f);return gi>=0?(ep.total[gi]||0):0;});
    const ea=calcEA(plArr,totArr);
    const plAcum=plArr.reduce((a,v)=>a+v,0);
    rows.push({label:p, ea, plAcum, isTotal:false});
  });

  // Subperíodos estándar (si hay datos suficientes)
  const subPeriodos=[
    {label:'Último mes',   dias:21},
    {label:'Últimos 3m',   dias:63},
    {label:'Últimos 6m',   dias:126},
    {label:'En el año',    dias:null}, // usa todo FF()
  ];

  // Calcular EA por subperíodo para el portafolio/total seleccionado
  const subRows=subPeriodos.map(sp=>{
    const n=sp.dias||dias;
    const fSlice=fechas.slice(-Math.min(n,dias));
    const idxs=fSlice.map(f=>D.fechas.indexOf(f));
    const getEAport=p=>{
      const ep=p?D.evol_port[p]:null;
      const plArr=idxs.map(i=>i>=0?(ep?ep.pl[i]:D.evol?.pl?.[i])||0:0);
      const totArr=idxs.map(i=>i>=0?(ep?ep.total[i]:D.evol?.total?.[i])||0:0);
      return calcEA(plArr,totArr);
    };
    const eaT=getEAport(null);
    const portEAs=ports.reduce((obj,p)=>{obj[p]=getEAport(p);return obj;},{});
    return {label:sp.label, eaTotal:eaT, portEAs, ndias:fSlice.length};
  });

  // Render tabla
  let html=`<table style="width:100%;border-collapse:collapse;font-size:12px">
    <thead><tr style="background:var(--s2)">
      <th style="padding:9px 14px;text-align:left;font-size:10px;text-transform:uppercase;letter-spacing:.5px;color:var(--tx2);border-bottom:1px solid var(--bd)">Portafolio / Período</th>
      <th style="padding:9px 14px;text-align:right;font-size:10px;text-transform:uppercase;letter-spacing:.5px;color:var(--tx2);border-bottom:1px solid var(--bd)">EA Período Seleccionado</th>
      <th style="padding:9px 14px;text-align:right;font-size:10px;text-transform:uppercase;letter-spacing:.5px;color:var(--tx2);border-bottom:1px solid var(--bd)">P&L Acumulado</th>
      ${subPeriodos.map(s=>`<th style="padding:9px 14px;text-align:right;font-size:10px;text-transform:uppercase;letter-spacing:.5px;color:var(--tx2);border-bottom:1px solid var(--bd)">${s.label}</th>`).join('')}
    </tr></thead><tbody>`;

  rows.forEach(r=>{
    const eaFmt=v=>v==null?'—':`<span style="font-weight:700;font-family:var(--mono);color:${v>=0?'var(--g)':'var(--r)'}">${v>=0?'+':''}${(v*100).toFixed(2)}%</span>`;
    const isT=r.isTotal;
    const portEAcols=subRows.map(sp=>{
      const v=isT?sp.eaTotal:(sp.portEAs?.[r.label]||null);
      return `<td style="padding:8px 14px;text-align:right;border-bottom:1px solid var(--bd)">${eaFmt(v)}</td>`;
    }).join('');
    html+=`<tr style="${isT?'background:var(--g4);font-weight:700':''}">
      <td style="padding:8px 14px;border-bottom:1px solid var(--bd);font-weight:${isT?700:500}">${isT?'<b>'+r.label+'</b>':r.label}</td>
      <td style="padding:8px 14px;text-align:right;border-bottom:1px solid var(--bd)">${eaFmt(r.ea)}</td>
      <td style="padding:8px 14px;text-align:right;border-bottom:1px solid var(--bd);font-family:var(--mono);color:${r.plAcum>=0?'var(--g)':'var(--r)'}">${sgn(r.plAcum)+fC(r.plAcum)}</td>
      ${portEAcols}
    </tr>`;
  });
  html+=`</tbody></table>`;
  cont.innerHTML=html;
}

// ════════════════════════════════════════════════════════════
// TAB ②  COMPOSICIÓN — Power BI style
// La tabla maestra es la fuente de verdad; filtra las gráficas
// ════════════════════════════════════════════════════════════
let _compSub = 'tipo';
let _compChips = new Set();
let _compSelRows = new Set(); // índices de filas seleccionadas en la tabla

function setCS(btn){
  document.querySelectorAll('#compST .stab').forEach(b=>b.classList.remove('on'));
  btn.classList.add('on'); _compSub=btn.dataset.c;
  _compUpdateCharts(_compGetActiveRows());
}

function _compChip(btn){
  btn.classList.toggle('on');
  const k=btn.dataset.cf;
  if(_compChips.has(k)) _compChips.delete(k); else _compChips.add(k);
  _compSelRows.clear();
  _compTableRender();
}

function _compClearSel(){
  _compSelRows.clear();
  _compChips.clear();
  document.querySelectorAll('#pg-composicion .chip.on').forEach(b=>b.classList.remove('on'));
  const q=document.getElementById('compQ'); if(q) q.value='';
  _compTableRender();
}

// Devuelve las filas activas según chips + búsqueda + selección
function _compGetActiveRows(){
  let rows=FD();
  const q=(document.getElementById('compQ')?.value||'').toLowerCase();
  if(q) rows=rows.filter(r=>(r.esp||'').toLowerCase().includes(q)||(r.isin||'').toLowerCase().includes(q)||(r.port||'').toLowerCase().includes(q));
  if(_compChips.has('rf'))     rows=rows.filter(r=>['TES','TIDIS','CDT','Titularizaciones'].includes(r.tipo));
  if(_compChips.has('fondos')) rows=rows.filter(r=>r.tipo==='Fondos');
  if(_compChips.has('liq'))    rows=rows.filter(r=>r.tipo==='Liquidez');
  if(_compChips.has('vcto90')) rows=rows.filter(r=>r.dias_vcto>0&&r.dias_vcto<=90);
  if(_compChips.has('ext'))    rows=rows.filter(r=>r.ext);
  if(_compChips.has('neg'))    rows=rows.filter(r=>(r.pl||0)<0);
  if(_compChips.has('top10'))  rows=[...rows].sort((a,b)=>(b.valor||0)-(a.valor||0)).slice(0,10);
  // Si hay filas seleccionadas en la tabla, filtrar por ellas
  if(_compSelRows.size>0) rows=rows.filter((_,i)=>_compSelRows.has(i));
  return rows;
}

// Actualiza gráficas con el subconjunto de filas dado
function _compUpdateCharts(rows){
  const ttlTotal=FD().reduce((a,r)=>a+(r.valor||0),0);
  const ttl=rows.reduce((a,r)=>a+(r.valor||0),0);

  // KPIs de selección
  const pl=rows.reduce((a,r)=>a+(r.pl||0),0);
  const cmer=rows.reduce((a,r)=>a+(r.caus_mer||0),0);
  const ctir=rows.reduce((a,r)=>a+(r.caus_tir||0),0);
  const cmon=rows.reduce((a,r)=>a+(r.caus_mon||0),0);
  const kpiEl=document.getElementById('compKpis');
  if(kpiEl) kpiEl.innerHTML=
    kH('Valor selección',fC(ttl),null,null,'#00854A',`${fP(ttlTotal?ttl/ttlTotal*100:0)} del total`)+
    kH('P&L del día',fC(pl),null,pl,'#00854A',rows.length+' posiciones')+
    kH('Caus. Mercado',fC(cmer),null,cmer,'#3b82f6','Devengado precio')+
    kH('Caus. TIR',fC(ctir),null,ctir,'#3b82f6','Devengado TIR')+
    kH('Caus. FX',fC(cmon),null,cmon,'#f97316','Efecto cambio');

  // Agrupar por el sub activo
  const grpKey={tipo:'tipo',port:'port',moneda:'moneda'}[_compSub]||'tipo';
  const byK={};
  rows.forEach(r=>{
    const k=r[grpKey]||'Otro';
    if(!byK[k]) byK[k]={total:0,pl:0,n:0};
    byK[k].total+=(r.valor||0); byK[k].pl+=(r.pl||0); byK[k].n++;
  });
  const sorted=Object.entries(byK).sort((a,b)=>b[1].total-a[1].total);
  const labels=sorted.map(([k])=>k);
  const colors=sorted.map(([k],i)=>grpKey==='tipo'?(TC[k]||PA[i%PA.length]):PC[i%PA.length]);
  const vals=sorted.map(([,v])=>v.total);

  // Donut
  document.getElementById('compDonutVal').textContent=fmt(ttl);
  document.getElementById('compDonutLbl').textContent=_compSelRows.size||_compChips.size?'filtrado':'total';
  const titMap={tipo:'Por Tipo',port:'Por Portafolio',moneda:'Por Moneda'};
  document.getElementById('compDonutTitle').textContent=titMap[_compSub]||'Por Tipo';
  mkC('cCompDonut',{type:'doughnut',data:{labels,datasets:[{
    data:vals,backgroundColor:colors,borderColor:'transparent',hoverOffset:6,borderRadius:3,spacing:2
  }]},options:{...CHART_DEFAULTS,cutout:'72%',
    onClick:(e,els)=>{ if(els.length){ const lbl=labels[els[0].index]; _compFilterByGroup(grpKey,lbl); } },
    plugins:{legend:{display:false},
      tooltip:{...tipFull(),callbacks:{label:c=>`${c.label}: ${fmt(c.raw)} · ${ttl?(c.raw/ttl*100).toFixed(1):0}%`}}}}});

  // Leyenda inline del donut
  const legEl=document.getElementById('compDonutLegend');
  if(legEl) legEl.innerHTML=sorted.slice(0,8).map(([k,v],i)=>{
    const pct=ttl?(v.total/ttl*100).toFixed(1):0;
    return `<div style="display:flex;align-items:center;gap:6px;font-size:10.5px;cursor:pointer" onclick="_compFilterByGroup('${grpKey}','${escAttr(k)}')">
      <div style="width:9px;height:9px;border-radius:50%;background:${colors[i]};flex-shrink:0"></div>
      <div style="flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;color:var(--tx2)" title="${escAttr(k)}">${escHtml(k)}</div>
      <div style="font-weight:700;font-family:var(--mono);color:var(--tx);flex-shrink:0">${pct}%</div>
    </div>`;
  }).join('');

  // Barras horizontales — click filtra
  document.getElementById('compBarTitle').textContent='Valor por '+({tipo:'tipo',port:'portafolio',moneda:'moneda'}[_compSub]||'tipo');
  mkC('cCompBar',{type:'bar',data:{
    labels:labels.map(l=>l.length>20?l.slice(0,20)+'…':l),
    datasets:[{label:'Valor',data:vals,
      backgroundColor:colors.map(c=>c+'cc'),borderColor:colors,borderWidth:1.5,
      borderRadius:5,borderSkipped:false}]
  },options:{...CHART_DEFAULTS,indexAxis:'y',
    onClick:(e,els)=>{ if(els.length) _compFilterByGroup(grpKey,labels[els[0].index]); },
    plugins:{legend:{display:false},tooltip:{...tipFull(),callbacks:{label:c=>`${fC(c.raw)} · ${ttl?(c.raw/ttl*100).toFixed(1):0}%`}}},
    scales:{x:{ticks:{callback:v=>fmt(v),color:tx2(),font:{size:10.5}},grid:{color:gc(),drawBorder:false}},
            y:{ticks:{color:tx2(),font:{size:10.5}},grid:{display:false}}}}});

  // Buckets de vencimiento con el subconjunto activo
  const buckets=[
    {label:'<30d',  min:0,   max:30,   col:'rgba(220,38,38,.8)'},
    {label:'30-90d',min:30,  max:90,   col:'rgba(217,119,6,.75)'},
    {label:'90-180d',min:90, max:180,  col:'rgba(245,158,11,.7)'},
    {label:'180d-1a',min:180,max:365,  col:'rgba(37,99,235,.75)'},
    {label:'1-2a',  min:365, max:730,  col:'rgba(124,58,237,.7)'},
    {label:'2-5a',  min:730, max:1825, col:'rgba(16,185,129,.7)'},
    {label:'>5a',   min:1825,max:Infinity,col:'rgba(6,182,212,.65)'},
  ];
  const bVals=buckets.map(b=>rows.filter(r=>r.dias_vcto>b.min&&r.dias_vcto<=b.max).reduce((a,r)=>a+(r.valor||0),0));
  const bNs  =buckets.map(b=>rows.filter(r=>r.dias_vcto>b.min&&r.dias_vcto<=b.max).length);
  const bAct =buckets.map((b,i)=>({...b,val:bVals[i],n:bNs[i]})).filter(b=>b.val>0);
  mkC('cVctoBucket',{type:'bar',data:{labels:bAct.map(b=>b.label),datasets:[{
    label:'Valor',data:bAct.map(b=>b.val),backgroundColor:bAct.map(b=>b.col),
    borderRadius:5,borderSkipped:false,barPercentage:.7
  }]},options:{...CHART_DEFAULTS,plugins:{legend:{display:false},
    tooltip:{...tipBI(),callbacks:{label:c=>`${fC(c.raw)} · ${bAct[c.dataIndex].n} posic.`}}},scales:axO()}});

  // Cross tabla
  _buildCrossTable(rows);
}

// Filtra la tabla por grupo al hacer click en gráfica
function _compFilterByGroup(key, val){
  _compChips.clear();
  document.querySelectorAll('#pg-composicion .chip.on').forEach(b=>b.classList.remove('on'));
  // Seleccionar en la tabla las filas que matchean
  const allRows=FD();
  _compSelRows.clear();
  allRows.forEach((r,i)=>{ if((r[key]||'Otro')===val) _compSelRows.add(i); });
  _compTableRender();
}

function _compTableRender(){
  const allRows=FD();
  const q=(document.getElementById('compQ')?.value||'').toLowerCase();
  const grp=document.getElementById('compGrp')?.value||'';

  // Filtrar por chips + búsqueda (sin considerar selección para mostrar todas las filas)
  let filtered=[...allRows];
  if(q) filtered=filtered.filter(r=>(r.esp||'').toLowerCase().includes(q)||(r.isin||'').toLowerCase().includes(q)||(r.port||'').toLowerCase().includes(q));
  if(_compChips.has('rf'))     filtered=filtered.filter(r=>['TES','TIDIS','CDT','Titularizaciones'].includes(r.tipo));
  if(_compChips.has('fondos')) filtered=filtered.filter(r=>r.tipo==='Fondos');
  if(_compChips.has('liq'))    filtered=filtered.filter(r=>r.tipo==='Liquidez');
  if(_compChips.has('vcto90')) filtered=filtered.filter(r=>r.dias_vcto>0&&r.dias_vcto<=90);
  if(_compChips.has('ext'))    filtered=filtered.filter(r=>r.ext);
  if(_compChips.has('neg'))    filtered=filtered.filter(r=>(r.pl||0)<0);
  if(_compChips.has('top10'))  filtered=[...filtered].sort((a,b)=>(b.valor||0)-(a.valor||0)).slice(0,10);

  // Ordenar
  const st=_mkTableSort('compMaster'); if(!st.k) st.k='valor';
  filtered=_sortRows(filtered,st,'valor');

  // Marcar índices seleccionados en el set original (para cruce con gráficas)
  const ttlAll=allRows.reduce((a,r)=>a+(r.valor||0),0);
  const selRows=_compSelRows.size>0 ? filtered.filter((_,i)=>_compSelRows.has(allRows.indexOf(filtered[i]))) : filtered;

  // Construir cabecera
  const H=(lbl,col,cls='')=>_thSort(lbl,'compMaster',col,cls);
  const headHtml=`<tr>
    <th style="width:20px;padding:9px 6px 9px 14px"><input type="checkbox" id="compChkAll" onchange="_compToggleAll(this)" style="cursor:pointer"></th>
    ${H('Especie','esp')} ${H('Portafolio','port')} ${H('Tipo','tipo')} ${H('Moneda','moneda','r')}
    ${H('Nominal','nominal','r')} ${H('Valor Mercado','valor','r')} ${H('% Total','pct','r')}
    ${H('P&L Día','pl','r')} ${H('Caus. Mer','caus_mer','r')} ${H('Caus. TIR','caus_tir','r')}
    ${H('Caus. FX','caus_mon','r')} ${H('Caus. Tasa','caus_tasa','r')}
    ${H('TIR%','tir','r')} ${H('Precio','precio','r')} ${H('Adeudados','adeudados','r')}
    ${H('Vencimiento','vcto','')} ${H('Días','dias_vcto','r')} ${H('ISIN','isin','')} ${H('Estado','est','')}
  </tr>`;

  // Construir body
  let bodyHtml='';
  const grpMap={};

  filtered.forEach((r,localIdx)=>{
    const origIdx=allRows.indexOf(r);
    const isSel=_compSelRows.size===0||_compSelRows.has(origIdx);
    const dv=r.dias_vcto;
    const dvStyle=dv>0&&dv<=30?'color:var(--r);font-weight:700':dv>0&&dv<=90?'color:var(--y);font-weight:600':'';
    const rowStyle=isSel?'':'opacity:.45';
    const selStyle=_compSelRows.has(origIdx)?'background:rgba(0,133,74,.06)':'';
    const pct=ttlAll?(r.valor||0)/ttlAll*100:0;

    // Si hay agrupación, insertar fila de grupo
    if(grp && r[grp]){
      const gKey=r[grp];
      if(!grpMap[gKey]){
        grpMap[gKey]=true;
        const gRows=filtered.filter(rr=>rr[grp]===gKey);
        const gTotal=gRows.reduce((a,rr)=>a+(rr.valor||0),0);
        const gPl=gRows.reduce((a,rr)=>a+(rr.pl||0),0);
        bodyHtml+=`<tr style="background:var(--s2);font-weight:700">
          <td></td>
          <td colspan="5" style="padding:7px 14px;font-size:11px;text-transform:uppercase;letter-spacing:.5px">
            <span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:${grp==='tipo'?(TC[gKey]||'#888'):'var(--g)'};margin-right:6px"></span>
            ${escHtml(gKey)} — ${gRows.length} posiciones
          </td>
          <td class="r" style="padding:7px 14px">${fC(gTotal)}</td>
          <td class="r" style="padding:7px 14px">${fP(ttlAll?gTotal/ttlAll*100:0)}</td>
          <td class="${clr(gPl)}" style="padding:7px 14px">${sgn(gPl)+fC(gPl)}</td>
          <td colspan="10"></td>
        </tr>`;
      }
    }

    bodyHtml+=`<tr style="${rowStyle};${selStyle};cursor:pointer" onclick="_compToggleRow(${origIdx},event)">
      <td style="padding:8px 6px 8px 14px"><input type="checkbox" ${_compSelRows.has(origIdx)?'checked':''} onchange="_compToggleRow(${origIdx},event)" style="cursor:pointer" onclick="event.stopPropagation()"></td>
      <td class="main" title="${escAttr(r.esp)}" style="max-width:200px">${r.esp.length>32?r.esp.slice(0,32)+'…':escHtml(r.esp)}</td>
      <td style="white-space:nowrap">${escHtml(r.port||'—')}</td>
      <td>${bdg(r.tipo)}</td>
      <td class="mono" style="font-size:10.5px">${escHtml(r.moneda||'—')}</td>
      <td class="r">${fC(r.nominal)}</td>
      <td class="r" style="font-weight:700">${fC(r.valor)}</td>
      <td class="r" style="color:var(--tx2)">${fP(pct)}</td>
      <td class="${clr(r.pl)}">${r.pl!=null?sgn(r.pl)+fC(r.pl):'—'}</td>
      <td class="${clr(r.caus_mer)}">${fC(r.caus_mer)}</td>
      <td class="${clr(r.caus_tir)}">${fC(r.caus_tir)}</td>
      <td class="${clr(r.caus_mon)}">${fC(r.caus_mon)}</td>
      <td class="${clr(r.caus_tasa||0)}">${fC(r.caus_tasa)}</td>
      <td class="r" style="color:var(--b)">${r.tir>0.0001?fP(r.tir*100):'—'}</td>
      <td class="r mono" style="font-size:10.5px">${r.precio!=null?r.precio.toFixed(4):'—'}</td>
      <td class="r">${fC(r.adeudados)}</td>
      <td style="font-size:11px;${dvStyle};white-space:nowrap">${r.vcto||'—'}</td>
      <td class="r" style="${dvStyle}">${dv>0?dv:'—'}</td>
      <td class="mono" style="font-size:10.5px;color:var(--tx2)">${escHtml(r.isin||'—')}</td>
      <td>${estC(r.est)}</td>
    </tr>`;
  });

  // Tfoot
  const activePl=selRows.reduce((a,r)=>a+(r.pl||0),0);
  const activeTotal=selRows.reduce((a,r)=>a+(r.valor||0),0);
  const footHtml=`<tr>
    <td></td>
    <td colspan="5" style="padding:9px 14px;font-weight:700">TOTAL (${filtered.length} posiciones)</td>
    <td class="r" style="font-weight:700;font-family:var(--mono)">${fC(activeTotal)}</td>
    <td class="r">${fP(ttlAll?activeTotal/ttlAll*100:0)}</td>
    <td class="${clr(activePl)}" style="font-weight:700">${sgn(activePl)+fC(activePl)}</td>
    <td colspan="10"></td>
  </tr>`;

  const headEl=document.getElementById('compMasterHead');
  const bodyEl=document.getElementById('compMasterBody');
  const footEl=document.getElementById('compMasterFoot');
  if(headEl) headEl.innerHTML=headHtml;
  if(bodyEl) bodyEl.innerHTML=bodyHtml;
  if(footEl) footEl.innerHTML=footHtml;

  // Footer stats
  const nSel=_compSelRows.size;
  document.getElementById('compMasterCnt').textContent=filtered.length+' posiciones';
  document.getElementById('compSelInfo').textContent=nSel>0?nSel+' seleccionadas':'';
  document.getElementById('compMasterTotal').textContent=fC(activeTotal);
  const plEl=document.getElementById('compMasterPL');
  if(plEl){plEl.textContent=sgn(activePl)+fC(activePl);plEl.style.color=activePl>=0?'var(--g)':'var(--r)';}
  document.getElementById('compMasterPct').textContent=fP(ttlAll?activeTotal/ttlAll*100:0);

  // Actualizar gráficas con el subconjunto activo
  _compUpdateCharts(selRows);
}

function _compToggleRow(origIdx, e){
  if(e) e.stopPropagation();
  if(_compSelRows.has(origIdx)) _compSelRows.delete(origIdx);
  else _compSelRows.add(origIdx);
  _compTableRender();
}

function _compToggleAll(chk){
  const allRows=FD();
  if(chk.checked){ allRows.forEach((_,i)=>_compSelRows.add(i)); }
  else _compSelRows.clear();
  _compTableRender();
}

function _compSortBy(k){
  if(!S.tableSort)S.tableSort={};
  const st=S.tableSort.compTable||(S.tableSort.compTable={k:'total',d:-1});
  if(st.k===k) st.d*=-1; else{st.k=k;st.d=-1;}
  S.tableSort.compTable=st;
  _compTableRender();
}
function initComposicion(){ _compSub='tipo'; _compSelRows.clear(); _compChips.clear(); _compTableRender(); }

function _buildCrossTable(rowsOverride){
  const rows=rowsOverride||FD();
  // Calcular cross desde las rows activas (respeta selección)
  const live={};
  rows.forEach(r=>{
    const p=r.port||'—'; const t=r.tipo||'Otro';
    if(!live[p]) live[p]={};
    live[p][t]=(live[p][t]||0)+(r.valor||0);
  });
  const allTipos=[...new Set(rows.map(r=>r.tipo||'Otro'))].sort();
  const allPorts=[...new Set(rows.map(r=>r.port||'—'))].sort();
  if(!allPorts.length){ document.getElementById('crossTable').innerHTML='<div style="padding:12px;color:var(--tx2);font-size:12px">Sin datos.</div>'; return; }
  const maxVal=Math.max(...allPorts.flatMap(p=>allTipos.map(t=>live[p]?.[t]||0)),1);
  let html=`<table><thead><tr><th>Portafolio</th>${allTipos.map(t=>`<th class="r">${bdg(t)}</th>`).join('')}<th class="r">Total</th></tr></thead><tbody>`;
  allPorts.forEach(p=>{
    const pTot=allTipos.reduce((a,t)=>a+(live[p]?.[t]||0),0);
    html+=`<tr><td style="font-weight:600">${escHtml(p)}</td>`;
    allTipos.forEach(t=>{
      const v=live[p]?.[t]||0;
      const pct=maxVal?Math.round(v/maxVal*100):0;
      const col=TC[t]||'#6b7280';
      html+=`<td class="r" style="position:relative">
        <div style="position:absolute;left:0;top:0;bottom:0;width:${pct}%;background:${col};opacity:.13;pointer-events:none"></div>
        <span style="position:relative">${v?fmt(v):'—'}</span></td>`;
    });
    html+=`<td class="r" style="font-weight:700;font-family:var(--mono)">${fmt(pTot)}</td></tr>`;
  });
  html+='</tbody></table>';
  document.getElementById('crossTable').innerHTML=html;
}


function _compSortBy(k){
  if(!S.tableSort)S.tableSort={};
  const st=S.tableSort.compTable||(S.tableSort.compTable={k:'total',d:-1});
  if(st.k===k) st.d*=-1; else{st.k=k;st.d=-1;}
  S.tableSort.compTable=st;
  _renderComp();
}
function initComposicion(){ _compSub='tipo'; _renderComp(); }

// ════════════════════════════════════════════════════════════
// TAB ③  EVOLUCIÓN
// ════════════════════════════════════════════════════════════
function initEvolucion(){
  // Stats período (reutiliza la misma lógica de antes)
  const ev=FE();
  const pl=ev.pl.filter(v=>v!=null);
  const plAcum=pl.reduce((a,v)=>a+v,0);
  const diasPos=pl.filter(v=>v>0).length;
  const diasNeg=pl.filter(v=>v<0).length;
  const avg=pl.length?pl.reduce((a,v)=>a+v,0)/pl.length:0;
  const std=pl.length>1?Math.sqrt(pl.reduce((a,v)=>a+Math.pow(v-avg,2),0)/(pl.length-1)):0;
  const sharpe=std>0?avg/std*Math.sqrt(252):0;
  let mdd=0,pk=ev.total[0]||0;
  ev.total.forEach(v=>{if(v>pk)pk=v;const d=pk>0?(pk-v)/pk*100:0;if(d>mdd)mdd=d;});

  document.getElementById('evolStats').innerHTML=[
    ['Período',`${ev.fechas[0]||'—'} → ${ev.fechas[ev.fechas.length-1]||'—'}`,''],
    ['Días',String(pl.length),''],
    ['Días +',String(diasPos),'pos'],
    ['Días −',String(diasNeg),'neg'],
    ['P&L acum.',fC(plAcum),plAcum>=0?'pos':'neg'],
    ['Prom/día',fC(avg),avg>=0?'pos':'neg'],
    ['Sharpe',sharpe.toFixed(3),sharpe>0.5?'pos':sharpe>0?'':'neg'],
    ['Drawdown',fP(mdd),'neg'],
  ].map(([l,v,c])=>`<div class="scell"><div class="sl">${l}</div><div class="sv ${c}">${v}</div></div>`).join('');

  // Poblar select de especies
  const espSel=document.getElementById('espSel');
  if(espSel.options.length===1){
    Object.keys(D.esp_hist)
      .sort((a,b)=>(D.esp_hist[b].total.reduce((x,v)=>x+(v||0),0))-(D.esp_hist[a].total.reduce((x,v)=>x+(v||0),0)))
      .slice(0,30).forEach(e=>{
        const o=document.createElement('option');o.value=e;
        o.textContent=e.length>34?e.slice(0,34)+'…':e;espSel.appendChild(o);
      });
  }

  RE();  // renderiza la gráfica evolutiva

  // Rentabilidad mensual — filtra por portafolio si está seleccionado
  let rmKeys, rmVals;
  if(S.f.port && D.evol_port[S.f.port]){
    // Calcular P&L mensual desde la serie del portafolio filtrado
    const ep=D.evol_port[S.f.port];
    const mesMap={};
    FF().forEach(f=>{
      const gi=D.fechas.indexOf(f);
      if(gi<0) return;
      const mes=f.slice(0,7);
      mesMap[mes]=(mesMap[mes]||0)+(ep.pl[gi]||0);
    });
    rmKeys=Object.keys(mesMap).sort();
    rmVals=rmKeys.map(k=>mesMap[k]);
  } else {
    const rm=D.extras?.rent_mensual||{};
    rmKeys=Object.keys(rm).sort();
    rmVals=rmKeys.map(k=>rm[k]);
  }
  mkC('cRentMes',{type:'bar',data:{labels:rmKeys.map(k=>k.slice(2)),datasets:[{
    label:'P&L mensual'+(S.f.port?' · '+S.f.port:''),data:rmVals,
    backgroundColor:rmVals.map(v=>v>=0?'rgba(0,200,110,.8)':'rgba(239,68,68,.8)'),
    borderRadius:5,borderSkipped:false,barPercentage:.7
  }]},options:{...CHART_DEFAULTS,plugins:{legend:{display:false},tooltip:tipBI()},scales:axO()}});

  // Nominal vs Mercado — usa datos del portafolio filtrado si hay selección
  const nomData = S.f.port && D.evol_port[S.f.port]
    ? FF().map(f=>{const gi=D.fechas.indexOf(f);return gi>=0?(D.evol_port[S.f.port].nominal?.[gi]||null):null;})
    : (D.extras?.nom_evol?.nominal||[]);
  mkC('cNomMer',{type:'line',data:{labels:dateL(ev.fechas),datasets:[
    {label:'Mercado'+(S.f.port?' · '+S.f.port:''),data:ev.total,borderColor:'#00c96e',
      backgroundColor:(ctx)=>{const g=ctx.chart.ctx.createLinearGradient(0,0,0,ctx.chart.height||260);g.addColorStop(0,'rgba(0,200,110,.2)');g.addColorStop(1,'rgba(0,200,110,0)');return g;},
      fill:true,tension:.4,pointRadius:0,pointHoverRadius:5,borderWidth:2.5},
    {label:'Nominal',data:nomData,borderColor:'rgba(96,165,250,.7)',
      backgroundColor:'transparent',tension:.4,pointRadius:0,borderWidth:1.5,borderDash:[5,3]},
  ]},options:{...CHART_DEFAULTS,plugins:{legend:leg('top'),tooltip:tipBI()},scales:axO()}});

  // Tabla de movimientos — ordenable
  _renderCambiosTable();
}

// Alias para compatibilidad con RE() que lee S.evol
function initEvolutivo(){ initEvolucion(); }

// ════════════════════════════════════════════════════════════
// ─── TABLAS ORDENABLES DE TABS ────────────────────────────────
function _mkTableSort(key){
  if(!S.tableSort)S.tableSort={};
  return S.tableSort[key]||(S.tableSort[key]={k:null,d:-1});
}
function _sortRows(rows,st,defaultK){
  const k=st.k||defaultK;
  return [...rows].sort(function(a,b){
    const av=a[k],bv=b[k];
    if(av==null&&bv==null)return 0; if(av==null)return 1; if(bv==null)return -1;
    if(typeof av==='string') return av.localeCompare(bv)*st.d;
    return (av-bv)*st.d;
  });
}
function _thSort(label,stKey,col,cls){
  const st=_mkTableSort(stKey);
  const active=(st.k||col)===col;
  const arrow=active?(st.d>0?' ▲':' ▼'):'';
  return '<th class="'+(cls||'')+'" onclick="_tblSort(\''+stKey+'\',\''+col+'\')" style="cursor:pointer">'+label+arrow+'</th>';
}
function _tblSort(stKey,col){
  const st=_mkTableSort(stKey);
  if((st.k||col)===col) st.d*=-1; else{st.k=col;st.d=-1;}
  const renderMap={
    caus:      function(){_renderCausTable(FD());},
    rf:        function(){_renderRFTable(FD().filter(function(r){return ['TES','TIDIS','CDT','Titularizaciones'].includes(r.tipo);}));},
    cambios:   function(){_renderCambiosTable();},
    detalle:   function(){renderDetalle();},
    compVcto:  function(){_buildCompVctoTable();}
  };
  if(renderMap[stKey]) renderMap[stKey]();
}

// Tabla de causaciones
function _renderCausTable(rows){
  const st=_mkTableSort('caus'); if(!st.k)st.k='caus_mer_abs';
  const enriched=rows.map(function(r){return Object.assign({caus_mer_abs:Math.abs(r.caus_mer||0),diff:(r.caus_mer||0)-(r.caus_tir||0)},r);});
  const sorted=_sortRows(enriched,st,'caus_mer_abs');

  let head='<tr>';
  head+=_thSort('Especie','caus','esp','');
  head+=_thSort('Portafolio','caus','port','');
  head+=_thSort('Tipo','caus','tipo','');
  head+=_thSort('Caus. Mercado','caus','caus_mer','r');
  head+=_thSort('Caus. TIR','caus','caus_tir','r');
  head+=_thSort('Dif. M−TIR','caus','diff','r');
  head+=_thSort('Caus. FX','caus','caus_mon','r');
  head+=_thSort('Caus. Tasa','caus','caus_tasa','r');
  head+=_thSort('Adeudados','caus','adeudados','r');
  head+=_thSort('Valor Mdo','caus','valor','r');
  head+='</tr>';

  let body='';
  sorted.slice(0,80).forEach(function(r){
    const espS=r.esp.length>28?r.esp.slice(0,28)+'…':r.esp;
    body+='<tr>';
    body+='<td class="main" title="'+escAttr(r.esp)+'">'+espS+'</td>';
    body+='<td>'+escHtml(r.port||'—')+'</td>';
    body+='<td>'+bdg(r.tipo)+'</td>';
    body+='<td class="'+clr(r.caus_mer)+'">'+fC(r.caus_mer)+'</td>';
    body+='<td class="'+clr(r.caus_tir)+'">'+fC(r.caus_tir)+'</td>';
    body+='<td class="'+clr(r.diff)+'">'+fC(r.diff)+'</td>';
    body+='<td class="'+clr(r.caus_mon)+'">'+fC(r.caus_mon)+'</td>';
    body+='<td class="'+clr(r.caus_tasa)+'">'+fC(r.caus_tasa)+'</td>';
    body+='<td class="r">'+fC(r.adeudados)+'</td>';
    body+='<td class="r">'+fC(r.valor)+'</td>';
    body+='</tr>';
  });

  const container=document.getElementById('tCausBody');
  if(container){
    // Actualizar header también
    const tbl=container.closest('table');
    if(tbl){
      const thead=tbl.querySelector('thead tr');
      if(thead) thead.outerHTML=head;
    }
    container.innerHTML=body;
  }
}

// Tabla de renta fija
function _renderRFTable(rf){
  const st=_mkTableSort('rf'); if(!st.k)st.k='valor';
  const sorted=_sortRows(rf,st,'valor');

  let head='<tr>';
  head+=_thSort('ISIN','rf','isin','');
  head+=_thSort('Especie','rf','esp','');
  head+=_thSort('Portafolio','rf','port','');
  head+=_thSort('Tipo','rf','tipo','');
  head+=_thSort('Nominal','rf','nominal','r');
  head+=_thSort('Precio','rf','precio','r');
  head+=_thSort('TIR%','rf','tir','r');
  head+=_thSort('Facial','rf','facial','');
  head+=_thSort('Modalidad','rf','mod','');
  head+=_thSort('Vencimiento','rf','vcto','');
  head+=_thSort('Días','rf','dias_vcto','r');
  head+=_thSort('Valor Mdo','rf','valor','r');
  head+=_thSort('P&L','rf','pl','r');
  head+=_thSort('Caus. Mer','rf','caus_mer','r');
  head+=_thSort('Caus. TIR','rf','caus_tir','r');
  head+=_thSort('Adeudados','rf','adeudados','r');
  head+='</tr>';

  let body='';
  sorted.forEach(function(r){
    body+='<tr>';
    body+='<td class="mono">'+(r.isin||'—')+'</td>';
    body+='<td class="main" title="'+escAttr(r.esp)+'">'+(r.esp.length>24?r.esp.slice(0,24)+'…':r.esp)+'</td>';
    body+='<td>'+escHtml(r.port||'—')+'</td>';
    body+='<td>'+bdg(r.tipo)+'</td>';
    body+='<td class="r">'+fC(r.nominal)+'</td>';
    body+='<td class="r">'+(r.precio!=null?r.precio.toFixed(3):'—')+'</td>';
    body+='<td class="r" style="color:var(--b);font-weight:700">'+(r.tir&&r.tir>0.0001?fP(r.tir*100):'—')+'</td>';
    body+='<td style="font-size:10px;color:var(--tx2)">'+(r.facial||'—')+'</td>';
    body+='<td style="font-size:11px">'+(r.mod||'—')+'</td>';
    body+='<td style="font-size:11px">'+(r.vcto||'—')+'</td>';
    body+='<td class="r">'+(r.dias_vcto!=null?Math.round(r.dias_vcto):'—')+'</td>';
    body+='<td class="r">'+fC(r.valor)+'</td>';
    body+='<td class="'+clr(r.pl)+'">'+(r.pl!=null?sgn(r.pl)+fC(r.pl):'—')+'</td>';
    body+='<td class="'+clr(r.caus_mer)+'">'+fC(r.caus_mer)+'</td>';
    body+='<td class="'+clr(r.caus_tir)+'">'+fC(r.caus_tir)+'</td>';
    body+='<td class="r">'+fC(r.adeudados)+'</td>';
    body+='</tr>';
  });

  const container=document.getElementById('tRFBody');
  if(container){
    const tbl=container.closest('table');
    if(tbl){const thead=tbl.querySelector('thead tr');if(thead)thead.outerHTML=head;}
    container.innerHTML=body;
  }
}

// Tabla de cambios / movimientos (Tab Evolución)
function _renderCambiosTable(){
  const allEsp=[...new Set(applyTipoMap(D.tabla).map(function(r){return r.esp;}))];
  const cambios=[];
  allEsp.forEach(function(esp){
    const h=D.esp_hist[esp]; if(!h)return;
    const filtF=FF();
    const idx0=h.fechas.indexOf(filtF[0]);
    const idxN=h.fechas.indexOf(filtF[filtF.length-1]);
    if(idx0<0||idxN<0)return;
    const v0=h.total[idx0]||0,vN=h.total[idxN]||0;
    const plTotal=filtF.reduce(function(a,f){const i=h.fechas.indexOf(f);return a+(i>=0?(h.pl[i]||0):0);},0);
    const row=applyTipoMap(D.tabla).find(function(r){return r.esp===esp;});
    const varPct=v0?(vN-v0)/v0*100:0;
    if(Math.abs(varPct)>0.5||row?.est==='Vendido')
      cambios.push({esp,port:row?.port||'',tipo:row?.tipo||'',est:row?.est||'',v0,vN,varPct,plTotal});
  });

  const st=_mkTableSort('cambios'); if(!st.k)st.k='varPct_abs';
  const enriched=cambios.map(function(c){return Object.assign({varPct_abs:Math.abs(c.varPct),plTotal_abs:Math.abs(c.plTotal)},c);});
  const sorted=_sortRows(enriched,st,'varPct_abs');

  let head='<tr>';
  head+=_thSort('Especie','cambios','esp','');
  head+=_thSort('Portafolio','cambios','port','');
  head+=_thSort('Tipo','cambios','tipo','');
  head+=_thSort('Estado','cambios','est','');
  head+=_thSort('Valor Inicial','cambios','v0','r');
  head+=_thSort('Valor Final','cambios','vN','r');
  head+=_thSort('Variación %','cambios','varPct','r');
  head+=_thSort('P&L Total','cambios','plTotal','r');
  head+='</tr>';

  let body='';
  sorted.slice(0,60).forEach(function(c){
    body+='<tr>';
    body+='<td class="main" title="'+escAttr(c.esp)+'">'+(c.esp.length>28?c.esp.slice(0,28)+'…':c.esp)+'</td>';
    body+='<td>'+escHtml(c.port)+'</td>';
    body+='<td>'+bdg(c.tipo)+'</td>';
    body+='<td>'+estC(c.est)+'</td>';
    body+='<td class="r">'+fC(c.v0)+'</td>';
    body+='<td class="r">'+fC(c.vN)+'</td>';
    body+='<td class="'+clr(c.varPct)+'">'+sgn(c.varPct)+fP(c.varPct)+'</td>';
    body+='<td class="'+clr(c.plTotal)+'">'+sgn(c.plTotal)+fC(c.plTotal)+'</td>';
    body+='</tr>';
  });

  const container=document.getElementById('tCambios');
  if(container){
    const tbl=container.closest('table');
    if(tbl){const thead=tbl.querySelector('thead tr');if(thead)thead.outerHTML=head;}
    container.innerHTML=body;
  }
}

// ════════════════════════════════════════════════════════════
// TAB ④  RENDIMIENTO
// ════════════════════════════════════════════════════════════
function initRendimiento(){
  const rows=FD(), ev=FE(), lbs=dateL(ev.fechas);
  const s=D.stats||{};

  // KPIs de rendimiento/riesgo
  document.getElementById('kpiRend').innerHTML=
    kH('Hit Rate',s.hit_rate!=null?fP(s.hit_rate):'—',null,s.hit_rate>50?1:-1,'#00854A',`${s.dias_pos||0}d pos / ${s.dias_neg||0}d neg`)+
    kH('Volatilidad Anual',s.vol_anual!=null?fC(s.vol_anual):'—',null,null,'#3b82f6','P&L std × √252')+
    kH('Sharpe Anualizado',s.sharpe!=null?s.sharpe.toFixed(3):'—',null,s.sharpe,'#8b5cf6','Ajustado por volatilidad')+
    kH('Drawdown Máx.',s.drawdown!=null?fP(s.drawdown):'—',null,-1,'#ef4444','Caída máxima del período');

  // KPIs causaciones
  const cmer=rows.reduce((a,r)=>a+(r.caus_mer||0),0);
  const ctir=rows.reduce((a,r)=>a+(r.caus_tir||0),0);
  const cmon=rows.reduce((a,r)=>a+(r.caus_mon||0),0);
  const ctasa=rows.reduce((a,r)=>a+(r.caus_tasa||0),0);
  document.getElementById('kpiCaus').innerHTML=
    kH('Caus. Mercado',fC(cmer),null,cmer,'#00854A','Total devengado a mercado')+
    kH('Caus. TIR',fC(ctir),null,ctir,'#3b82f6','Devengado teórico')+
    kH('Diferencia M−TIR',fC(cmer-ctir),null,cmer-ctir,'#f59e0b','Efecto precio de mercado')+
    kH('Caus. FX',fC(cmon),null,cmon,'#8b5cf6','Efecto tipo de cambio');

  // Evolución causaciones
  mkC('cCausE',{type:'line',data:{labels:lbs,datasets:[
    {label:'Mercado',data:ev.caus_mer,borderColor:'#00c96e',
      backgroundColor:(ctx)=>{const g=ctx.chart.ctx.createLinearGradient(0,0,0,ctx.chart.height||280);g.addColorStop(0,'rgba(0,200,110,.15)');g.addColorStop(1,'rgba(0,200,110,0)');return g;},
      fill:true,tension:.4,pointRadius:0,borderWidth:2.5},
    {label:'TIR',data:ev.caus_tir,borderColor:'#60a5fa',backgroundColor:'transparent',tension:.4,pointRadius:0,borderWidth:2,borderDash:[6,3]},
    {label:'FX',data:ev.caus_mon,borderColor:'#fbbf24',backgroundColor:'transparent',tension:.4,pointRadius:0,borderWidth:2},
    {label:'Tasa',data:ev.caus_tasa,borderColor:'#a78bfa',backgroundColor:'transparent',tension:.4,pointRadius:0,borderWidth:2,borderDash:[3,3]},
  ]},options:{...CHART_DEFAULTS,plugins:{legend:leg('top'),tooltip:tipBI()},scales:axO()}});

  const ac1=ev.caus_mer.reduce((a,v,i)=>{a.push((a[i-1]||0)+v);return a;},[]);
  const ac2=ev.caus_tir.reduce((a,v,i)=>{a.push((a[i-1]||0)+v);return a;},[]);
  mkC('cCausAc',{type:'line',data:{labels:lbs,datasets:[
    {label:'Mercado Acum.',data:ac1,borderColor:'#00c96e',
      backgroundColor:(ctx)=>{const g=ctx.chart.ctx.createLinearGradient(0,0,0,ctx.chart.height||280);g.addColorStop(0,'rgba(0,200,110,.2)');g.addColorStop(1,'rgba(0,200,110,0)');return g;},
      fill:true,tension:.4,pointRadius:0,borderWidth:2.5},
    {label:'TIR Acum.',data:ac2,borderColor:'#60a5fa',backgroundColor:'transparent',tension:.4,pointRadius:0,borderWidth:2,borderDash:[6,3]},
  ]},options:{...CHART_DEFAULTS,plugins:{legend:leg('top'),tooltip:tipBI()},scales:axO()}});

  const byP2={};
  rows.forEach(r=>{
    if(!byP2[r.port])byP2[r.port]={m:0,t:0,fx:0};
    byP2[r.port].m+=(r.caus_mer||0);byP2[r.port].t+=(r.caus_tir||0);byP2[r.port].fx+=(r.caus_mon||0);
  });
  const pu2=Object.keys(byP2);
  mkC('cCausP',{type:'bar',data:{labels:pu2,datasets:[
    {label:'Mercado',data:pu2.map(p=>byP2[p].m),backgroundColor:'rgba(0,200,110,.8)',borderRadius:5,borderSkipped:false},
    {label:'TIR',data:pu2.map(p=>byP2[p].t),backgroundColor:'rgba(96,165,250,.7)',borderRadius:5,borderSkipped:false},
    {label:'FX',data:pu2.map(p=>byP2[p].fx),backgroundColor:'rgba(251,191,36,.7)',borderRadius:5,borderSkipped:false},
  ]},options:{...CHART_DEFAULTS,plugins:{legend:leg('top'),tooltip:tipBI()},scales:axO()}});

  const byT2={};
  rows.forEach(r=>{if(!byT2[r.tipo])byT2[r.tipo]={m:0,t:0};byT2[r.tipo].m+=(r.caus_mer||0);byT2[r.tipo].t+=(r.caus_tir||0);});
  const tu2=Object.keys(byT2).sort((a,b)=>Math.abs(byT2[b].m)-Math.abs(byT2[a].m));
  mkC('cCausT',{type:'bar',data:{labels:tu2,datasets:[
    {label:'Mercado',data:tu2.map(t=>byT2[t].m),backgroundColor:tu2.map(t=>TC[t]||'#6b7280'),borderRadius:5,borderSkipped:false},
    {label:'TIR',data:tu2.map(t=>byT2[t].t),backgroundColor:'rgba(96,165,250,.4)',borderRadius:5,borderSkipped:false},
  ]},options:{...CHART_DEFAULTS,plugins:{legend:leg('top'),tooltip:tipBI()},scales:axO()}});

  // Histograma P&L
  const pl_vals=ev.pl.filter(v=>v!=null);
  if(pl_vals.length>1){
    const mn=Math.min(...pl_vals),mx=Math.max(...pl_vals);
    const bins=12;const step=(mx-mn)/bins||1;
    const bCounts=Array(bins).fill(0);
    const bLabels=[];
    for(let i=0;i<bins;i++) bLabels.push(fmt(mn+i*step));
    pl_vals.forEach(v=>{let bi=Math.min(bins-1,Math.floor((v-mn)/step));bCounts[bi]++;});
    mkC('cHistPL',{type:'bar',data:{labels:bLabels,datasets:[{
      label:'Días',data:bCounts,
      backgroundColor:bLabels.map((_,i)=>mn+i*step>=0?'rgba(0,200,110,.75)':'rgba(239,68,68,.75)'),
      borderRadius:4,borderSkipped:false,categoryPercentage:1,barPercentage:.95
    }]},options:{...CHART_DEFAULTS,plugins:{legend:{display:false},tooltip:{...tipBI(),callbacks:{label:c=>`${c.raw} días`}}},
      scales:{x:{ticks:{color:tx2(),font:{size:9.5},maxRotation:45},grid:{display:false,drawBorder:false}},
              y:{ticks:{color:tx2(),font:{size:10.5}},grid:{color:gc(),drawBorder:false}}}}});
  }

  // Tabla causaciones — ordenable
  _renderCausTable(rows);
}

// Alias para compatibilidad (las funciones viejas podían llamarse)
function initCausaciones(){ initRendimiento(); }

// ════════════════════════════════════════════════════════════
// TAB ⑤  INSTRUMENTOS
// ════════════════════════════════════════════════════════════
function initInstrumentos(){
  const rf=FD().filter(r=>['TES','TIDIS','CDT','Titularizaciones'].includes(r.tipo));
  const total=rf.reduce((a,r)=>a+(r.valor||0),0);
  const mt=rf.filter(r=>r.tir&&r.tir>0.0001&&r.tir<30&&r.valor);
  const tirP=mt.length?mt.reduce((a,r)=>a+r.tir*(r.valor||0),0)/mt.reduce((a,r)=>a+(r.valor||0),0):null;
  const rd=rf.filter(r=>r.dias_vcto>0);
  const durP=rd.length?rd.reduce((a,r)=>a+r.dias_vcto*(r.valor||0),0)/rd.reduce((a,r)=>a+(r.valor||0),0):null;
  const precP=rf.filter(r=>r.precio).reduce((s,r,_,a)=>s+r.precio/a.length,0);

  document.getElementById('kpiRF').innerHTML=
    kH('Total RF',fC(total),null,null,'#3b82f6','TES+TIDIS+CDT+Titularizaciones')+
    kH('TIR Ponderada',tirP?fP(tirP*100):'—',null,null,'#00854A','Por valor de mercado')+
    kH('Precio Promedio',precP?precP.toFixed(3):'—',null,null,'#f59e0b','')+
    kH('Duración (días)',durP?Math.round(durP)+'d':'—',null,null,'#8b5cf6','Ponderada por valor');

  // Curva TIR vs días (bubble con colores por urgencia)
  const pts=rf.filter(r=>r.dias_vcto>0&&r.tir>0.0001&&r.tir<30).map(r=>({
    x:r.dias_vcto,y:r.tir*100,r:Math.max(5,Math.sqrt((r.valor||0)/3e8)*5),
    label:r.esp,val:r.valor,dias:r.dias_vcto
  }));
  const ptC=pts.map(p=>p.dias<90?'rgba(239,68,68,.65)':p.dias<365?'rgba(245,158,11,.6)':'rgba(59,130,246,.55)');
  const ptB=pts.map(p=>p.dias<90?'#ef4444':p.dias<365?'#f59e0b':'#3b82f6');
  mkC('cCurva',{type:'bubble',data:{datasets:[{label:'RF',data:pts,backgroundColor:ptC,borderColor:ptB,borderWidth:1.5}]},
    options:{...CHART_DEFAULTS,plugins:{legend:{display:false},tooltip:{backgroundColor:tipBg(),borderColor:tipBd(),borderWidth:1,
      titleColor:tipTx(),bodyColor:tipTx2(),padding:11,cornerRadius:9,
      callbacks:{label:c=>[`${c.raw.label}`,`TIR: ${c.raw.y.toFixed(2)}%  |  ${Math.round(c.raw.x)}d`,`Valor: ${fC(c.raw.val)}`]}}},
    scales:{
      x:{title:{display:true,text:'Días al Vencimiento',color:tx2(),font:{size:11}},
         ticks:{color:tx2(),font:{size:10.5}},grid:{color:gc(),drawBorder:false}},
      y:{title:{display:true,text:'TIR %',color:tx2(),font:{size:11}},
         ticks:{color:tx2(),font:{size:10.5},callback:v=>v.toFixed(1)+'%'},grid:{color:gc(),drawBorder:false}}}}});

  // Concentración Top 10
  const conc=D.extras?.concentracion||[];
  mkC('cConc',{type:'bar',data:{
    labels:conc.map(c=>c.esp.length>20?c.esp.slice(0,20)+'…':c.esp),
    datasets:[{label:'Valor',data:conc.map(c=>c.valor),
      backgroundColor:conc.map((_,i)=>PC[i%PC.length]+'cc'),
      borderColor:conc.map((_,i)=>PC[i%PC.length]),borderWidth:1,borderRadius:5,borderSkipped:false}]
  },options:{...CHART_DEFAULTS,indexAxis:'y',plugins:{legend:{display:false},
    tooltip:{...tipBI(),callbacks:{label:c=>`${fC(c.raw)}  (${conc[c.dataIndex]?.pct?.toFixed(1)||''}%)`}}},
    scales:{x:{ticks:{callback:v=>fmt(v),color:tx2(),font:{size:10.5}},grid:{color:gc(),drawBorder:false}},
            y:{ticks:{color:tx2(),font:{size:10.5}},grid:{display:false}}}}});

  // Vencimientos — todos los instrumentos con fecha, sin límite de días
  const vctoRf=rf.filter(r=>r.dias_vcto>0).sort((a,b)=>a.dias_vcto-b.dias_vcto);
  const vctoColor=d=>d<30?'rgba(220,38,38,.85)':d<90?'rgba(217,119,6,.8)':d<365?'rgba(37,99,235,.75)':d<730?'rgba(124,58,237,.7)':'rgba(16,185,129,.7)';
  mkC('cVcto',{type:'bar',data:{labels:vctoRf.map(r=>r.vcto||r.esp.slice(0,14)),datasets:[{
    label:'Valor',data:vctoRf.map(r=>r.valor||0),
    backgroundColor:vctoRf.map(r=>vctoColor(r.dias_vcto)),
    borderRadius:5,borderSkipped:false,barPercentage:.75
  }]},options:{...CHART_DEFAULTS,plugins:{legend:{display:false},tooltip:{backgroundColor:tipBg(),borderColor:tipBd(),borderWidth:1,
    titleColor:tipTx(),bodyColor:tipTx2(),padding:10,cornerRadius:8,
    callbacks:{title:c=>c[0].label,label:c=>{const r=vctoRf[c.dataIndex];return['Valor: '+fC(c.raw),'Días: '+(r?.dias_vcto||'—'),'TIR: '+(r?.tir>0.0001?fP(r.tir*100):'—')];}}}},
    scales:{x:{ticks:{color:tx2(),font:{size:9.5},maxRotation:50,maxTicksLimit:20},grid:{display:false,drawBorder:false}},
            y:{ticks:{callback:v=>fmt(v),color:tx2(),font:{size:10.5}},grid:{color:gc(),drawBorder:false}}}}});

  // TIR histórica
  const topISIN=[...new Set(rf.map(r=>r.isin||r.esp).filter(Boolean))].slice(0,6);
  const tirDS=topISIN.map((code,i)=>{
    const espNom=(rf.find(r=>(r.isin||r.esp)===code)||{}).esp||'';
    const h=D.esp_hist[espNom];
    if(!h) return{label:code,data:[],hidden:true};
    const data=FF().map(f=>{const idx=h.fechas.indexOf(f);return(idx>=0&&h.tir[idx]!=null)?h.tir[idx]*100:null;});
    return{label:code.slice(0,16),data,borderColor:PA[i%PA.length],backgroundColor:'transparent',
      tension:.4,pointRadius:2,borderWidth:2,spanGaps:false};
  });
  mkC('cTirH',{type:'line',data:{labels:dateL(FF()),datasets:tirDS},options:{...CHART_DEFAULTS,
    plugins:{legend:leg('top'),tooltip:{...tipBI(),callbacks:{label:c=>c.dataset.label+': '+(c.raw!=null?c.raw.toFixed(2)+'%':'—')}}},
    scales:{x:{ticks:{color:tx2(),font:{size:10.5}},grid:{color:gc(),drawBorder:false}},
            y:{ticks:{color:tx2(),font:{size:10.5},callback:v=>v.toFixed(1)+'%'},grid:{color:gc(),drawBorder:false}}}}});

  // Valor por especie RF
  const byE={};rf.forEach(r=>{byE[r.esp]={v:(byE[r.esp]?.v||0)+(r.valor||0),tipo:r.tipo};});
  const sE=Object.entries(byE).sort((a,b)=>b[1].v-a[1].v).slice(0,14);
  mkC('cRFBar',{type:'bar',data:{labels:sE.map(([k])=>k.length>22?k.slice(0,22)+'…':k),
    datasets:[{label:'Valor',data:sE.map(([,v])=>v.v),
      backgroundColor:sE.map(([,v])=>(TC[v.tipo]||'#6b7280')+'bb'),
      borderColor:sE.map(([,v])=>TC[v.tipo]||'#6b7280'),borderWidth:1,borderRadius:5,borderSkipped:false}]
  },options:{...CHART_DEFAULTS,indexAxis:'y',plugins:{legend:{display:false},tooltip:{...tipFull(),callbacks:{label:c=>fC(c.raw)}}},
    scales:{x:{ticks:{callback:v=>fmt(v),color:tx2(),font:{size:10.5}},grid:{color:gc(),drawBorder:false}},
            y:{ticks:{color:tx2(),font:{size:10.5}},grid:{display:false}}}}});

  // Tabla RF — ordenable
  _renderRFTable(rf);
}

// Alias para compatibilidad
function initRentaFija(){ initInstrumentos(); }




function setES(btn){
  document.querySelectorAll('#evolST .stab').forEach(b=>b.classList.remove('on'));
  btn.classList.add('on'); S.evol.sub=btn.dataset.s;
  document.getElementById('espSel').style.display=S.evol.sub==='especies'?'block':'none';
  RE();
}
function setGran(btn){
  document.querySelectorAll('#granST .stab').forEach(b=>b.classList.remove('on'));
  btn.classList.add('on'); S.evol.gran=btn.dataset.g; RE();
}

function agg(fechas,vals){
  if(S.evol.gran==='diario') return{lbs:dateL(fechas),data:vals};
  if(S.evol.gran==='acumulado') return{lbs:dateL(fechas),data:vals.reduce((a,v,i)=>{a.push((a[i-1]||0)+v);return a;},[])};
  // semanal
  const wk={};const wkeys=[];
  fechas.forEach((f,i)=>{
    const d=new Date(f);const diff=d.getDate()-d.getDay()+(d.getDay()===0?-6:1);
    const mon=new Date(d);mon.setDate(diff);
    const k=mon.toISOString().slice(0,10);
    if(!wk[k]){wk[k]=0;wkeys.push(k);}
    wk[k]+=(vals[i]||0);
  });
  return{lbs:wkeys.map(k=>k.slice(5).replace('-','/')),data:wkeys.map(k=>wk[k])};
}

const evolTitles={
  valor:'Valor de Mercado Total',portafolios:'Valor por Portafolio',
  tipos:'Composición por Tipo de Activo',pl:'P&L del Período',especies:'Evolución por Especie'
};
function RE(){
  const ev=FE();
  const sub=S.evol.sub;
  document.getElementById('evolTitle').textContent=evolTitles[sub]||'';

  if(sub==='valor'){
    const ag=agg(ev.fechas,ev.total);
    mkC('cEvol',{type:'line',data:{labels:ag.lbs,datasets:[{
      label:'Valor Mercado',data:ag.data,
      borderColor:'#00854A',
      backgroundColor:(ctx)=>{
        const g=ctx.chart.ctx.createLinearGradient(0,0,0,ctx.chart.height||380);
        g.addColorStop(0,'rgba(0,133,74,.3)');g.addColorStop(1,'rgba(0,133,74,0)');return g;
      },
      fill:true,tension:.4,pointRadius:0,pointHoverRadius:7,borderWidth:2.5,
      pointHoverBackgroundColor:'#00c96e',pointHoverBorderColor:'#fff',pointHoverBorderWidth:2
    }]},options:{...CHART_DEFAULTS,
      plugins:{legend:{display:false},tooltip:{...tipFull(),mode:'index',intersect:false}},
      scales:axO()}});
  }
  else if(sub==='portafolios'){
    const lbs=dateL(ev.fechas);
    const ports=S.f.port?[S.f.port]:D.ports;
    const ds=ports.map((p,i)=>({
      label:p,
      data:ev.fechas.map(f=>{const ep=D.evol_port[p];if(!ep)return 0;const gi=D.fechas.indexOf(f);return gi>=0?(ep.total[gi]||0):0;}),
      borderColor:PC[i%PC.length],backgroundColor:'transparent',
      tension:.4,pointRadius:0,pointHoverRadius:6,borderWidth:2.5
    }));
    mkC('cEvol',{type:'line',data:{labels:lbs,datasets:ds},
      options:{...CHART_DEFAULTS,
        plugins:{legend:leg('top'),tooltip:tipBI()},scales:axO()}});
  }
  else if(sub==='tipos'){
    const lbs=dateL(ev.fechas);
    const tipos=S.f.tipo?[S.f.tipo]:D.tipos;
    const ds=tipos.map((t,i)=>({
      label:t,
      data:ev.fechas.map(f=>{const gi=D.fechas.indexOf(f);return gi>=0?(D.evol_tipo[t]?.[gi]||0):0;}),
      backgroundColor:TC[t]||PA[i%PA.length],
      borderColor:'transparent',
      fill:true,tension:.3,pointRadius:0,borderWidth:0
    }));
    mkC('cEvol',{type:'line',data:{labels:lbs,datasets:ds},
      options:{...CHART_DEFAULTS,
        plugins:{legend:{position:'right',labels:{color:tx2(),font:{size:11},usePointStyle:true,padding:10}},tooltip:tipBI()},
        scales:{x:{ticks:{color:tx2(),font:{size:10.5}},grid:{color:gc(),drawBorder:false}},
                y:{stacked:true,ticks:{color:tx2(),font:{size:10.5},callback:v=>fmt(v)},grid:{color:gc(),drawBorder:false}}}}});
  }
  else if(sub==='pl'){
    const ag=agg(ev.fechas,ev.pl);
    const agAc=ag.data.reduce((a,v,i)=>{a.push((a[i-1]||0)+v);return a;},[]);
    mkC('cEvol',{type:'bar',data:{labels:ag.lbs,datasets:[
      {label:'P&L',data:ag.data,yAxisID:'y',
        backgroundColor:ag.data.map(v=>v>=0?'rgba(0,200,110,.8)':'rgba(239,68,68,.8)'),
        borderRadius:4,borderSkipped:false,barPercentage:.7},
      {label:'Acumulado',data:agAc,yAxisID:'y2',type:'line',
        borderColor:'#a78bfa',backgroundColor:'transparent',tension:.4,pointRadius:0,borderWidth:2.5}
    ]},options:{...CHART_DEFAULTS,
      plugins:{legend:leg('top'),tooltip:tipBI()},
      scales:{x:{ticks:{color:tx2(),font:{size:10.5}},grid:{color:gc(),drawBorder:false}},
        y:{ticks:{color:tx2(),font:{size:10.5},callback:v=>fmt(v)},grid:{color:gc(),drawBorder:false}},
        y2:{position:'right',ticks:{color:'rgba(167,139,250,.7)',font:{size:10.5},callback:v=>fmt(v)},grid:{display:false}}
      }}});
  }
  else if(sub==='especies'){
    const selVal=document.getElementById('espSel').value;
    const esps=selVal==='__top5'
      ? Object.keys(D.esp_hist).sort((a,b)=>D.esp_hist[b].total.reduce((x,v)=>x+(v||0),0)-D.esp_hist[a].total.reduce((x,v)=>x+(v||0),0)).slice(0,5)
      : [selVal];
    const lbs=dateL(FF());
    const ds=esps.map((e,i)=>{
      const h=D.esp_hist[e];if(!h)return null;
      const data=FF().map(f=>{const idx=h.fechas.indexOf(f);return idx>=0?(h.total[idx]||null):null;});
      return{label:e.length>28?e.slice(0,28)+'…':e,data,
        borderColor:PA[i%PA.length],backgroundColor:'transparent',
        tension:.4,pointRadius:0,pointHoverRadius:6,borderWidth:2.5,spanGaps:false};
    }).filter(Boolean);
    mkC('cEvol',{type:'line',data:{labels:lbs,datasets:ds},
      options:{...CHART_DEFAULTS,
        plugins:{legend:leg('top'),tooltip:{...tipBI()}},
        scales:axO()}});
  }
}

// ════════════════════════════════════════════════════════════
// TAB 3: DETALLE
// ════════════════════════════════════════════════════════════
let dtChips=new Set();
let dtSort={k:'valor',d:-1};

function initDetalle(){ renderDetalle(); }

function toggleChip(btn, ns){
  const c=btn.dataset.c;
  if(ns==='dt'){
    if(dtChips.has(c)){dtChips.delete(c);btn.classList.remove('on');}
    else{dtChips.add(c);btn.classList.add('on');}
    renderDetalle();
  }
}

function sortDet(k){
  if(dtSort.k===k) dtSort.d*=-1; else{dtSort.k=k;dtSort.d=-1;}
  document.querySelectorAll('#tDet th').forEach(th=>{
    th.classList.remove('asc','desc');
    if(th.getAttribute('onclick')===`sortDet('${k}')`){
      th.classList.add(dtSort.d>0?'asc':'desc');
    }
  });
  renderDetalle();
}

function renderDetalle(){
  const q=(document.getElementById('dtQ')?.value||'').toLowerCase();
  let rows=FD().filter(r=>{
    if(q&&!r.esp.toLowerCase().includes(q)&&!(r.isin||'').toLowerCase().includes(q)&&!(r.port||'').toLowerCase().includes(q)) return false;
    if(dtChips.has('rf')   &&!['TES','TIDIS','CDT','Titularizaciones'].includes(r.tipo)) return false;
    if(dtChips.has('vcto') &&!(r.dias_vcto>0&&r.dias_vcto<90)) return false;
    if(dtChips.has('ext')  &&!r.ext) return false;
    if(dtChips.has('neg')  &&!(r.pl<0)) return false;
    if(dtChips.has('reci') &&r.est!=='En Cartera') return false;
    return true;
  });
  rows.sort((a,b)=>{
    const av=a[dtSort.k],bv=b[dtSort.k];
    if(av==null&&bv==null)return 0;
    if(av==null)return 1;if(bv==null)return -1;
    return av>bv?dtSort.d:-dtSort.d;
  });

  const totalVal=rows.reduce((a,r)=>a+(r.valor||0),0);
  const info=`${rows.length} posiciones`;
  document.getElementById('dtCnt').textContent=info;
  document.getElementById('dtCntBot').textContent=info;
  document.getElementById('dtTotal').textContent=`Total filtrado: ${fC(totalVal)}`;

  // Agrupar si se pide
  const grp=document.getElementById('dtGrp')?.value||'';
  let html='';
  if(grp){
    const groups={};
    rows.forEach(r=>{const k=grp==='port'?r.port:r.tipo;if(!groups[k])groups[k]=[];groups[k].push(r);});
    Object.entries(groups).sort((a,b)=>b[1].reduce((x,r)=>x+(r.valor||0),0)-a[1].reduce((x,r)=>x+(r.valor||0),0)).forEach(([k,rs])=>{
      const gTotal=rs.reduce((a,r)=>a+(r.valor||0),0);
      const gPL=rs.reduce((a,r)=>a+(r.pl||0),0);
      html+=`<tr style="background:var(--s2);font-weight:700">
        <td colspan="4" style="padding:8px 11px;font-size:11px;color:var(--tx2)">${k} — ${rs.length} posiciones</td>
        <td class="r">${fC(gTotal)}</td>
        <td class="${clr(gPL)}">${sgn(gPL)}${fC(gPL)}</td>
        <td colspan="17"></td></tr>`;
      html+=rs.map(r=>detRow(r)).join('');
    });
  } else {
    html=rows.map(r=>detRow(r)).join('');
  }
  document.getElementById('tDetBody').innerHTML=html;
}

function detRow(r){
  var h='<tr>';
  h+='<td class="main" title="'+escAttr(r.esp)+'">'+(r.esp.length>26?r.esp.slice(0,26)+'…':escHtml(r.esp))+'</td>';
  h+='<td>'+escHtml(r.port||'—')+'</td><td>'+bdg(r.tipo)+'</td>';
  h+='<td class="mono">'+(r.isin||'—')+'</td>';
  h+='<td class="r">'+fC(r.valor)+'</td>';
  h+='<td class="'+clr(r.pl)+'">'+(r.pl!=null?sgn(r.pl)+fC(r.pl):'—')+'</td>';
  h+='<td class="'+clr(r.rend)+'">'+(r.rend!=null?sgn(r.rend)+fP(r.rend):'—')+'</td>';
  h+='<td class="'+clr(r.caus_mer)+'">'+fC(r.caus_mer)+'</td>';
  h+='<td class="'+clr(r.caus_tir)+'">'+fC(r.caus_tir)+'</td>';
  h+='<td class="'+clr(r.caus_mon)+'">'+fC(r.caus_mon)+'</td>';
  h+='<td class="'+clr(r.caus_tasa)+'">'+fC(r.caus_tasa)+'</td>';
  h+='<td class="r">'+fC(r.adeudados)+'</td>';
  h+='<td class="r" style="color:var(--b)">'+(r.tir&&r.tir>0.0001?fP(r.tir*100):'—')+'</td>';
  h+='<td class="r">'+(r.precio!=null?f3(r.precio):'—')+'</td>';
  h+='<td class="r">'+fC(r.nominal)+'</td>';
  h+='<td style="font-size:11px">'+(r.vcto||'—')+'</td>';
  h+='<td class="r">'+(r.dias_vcto!=null?Math.round(r.dias_vcto):'—')+'</td>';
  h+='<td style="font-size:10px;color:var(--tx2)">'+(r.facial||'—')+'</td>';
  h+='<td style="font-size:11px">'+(r.mod||'—')+'</td>';
  h+='<td>'+estC(r.est)+'</td>';
  h+='<td style="font-size:11px">'+(r.moneda||'—')+'</td>';
  h+='<td class="'+clr(r.dif_fx)+'">'+(r.dif_fx&&r.dif_fx!==0?f3(r.dif_fx):'—')+'</td>';
  h+='<td class="r">'+(r.dias!=null?Math.round(r.dias):'—')+'</td>';
  h+='</tr>';
  return h;
}





