// EXPORT
// ════════════════════════════════════════════════════════════
function exportCSV(){
  const rows=FD();
  const cols=['esp','port','act','tipo','isin','valor','v_ant','pl','rend','caus_mer','caus_tir','caus_mon','caus_tasa','adeudados','tir','precio','nominal','moneda','dif_fx','vcto','dias_vcto','facial','mod','est','met','dias'];
  const hdr=['Especie','Portafolio','Tipo Activo','Tipo Instrumento','ISIN','Valor Mercado','Val Anterior','P&L','Rend%','Caus Mer','Caus TIR','Caus FX','Caus Tasa','Adeudados','TIR','Precio','Nominal','Moneda','Dif FX','Vencimiento','Días Vcto','Facial','Modalidad','Estado','Método','Días'];
  const csv=[hdr,...rows.map(r=>cols.map(c=>r[c]!=null?String(r[c]):''))].map(r=>r.map(v=>'"'+String(v).replace(/"/g,'""')+'"').join(',')).join('\n');
  const blob=new Blob(['﻿'+csv],{type:'text/csv;charset=utf-8'});
  const a=document.createElement('a');a.href=URL.createObjectURL(blob);
  a.download=`posiciones_${D.meta.ultimo_dia}.csv`;a.click();
}
async function exportPDF(){
  try{
    const {jsPDF}=window.jspdf;
    const canvas=await html2canvas(document.getElementById('main'),
      {scale:1.5,useCORS:true,backgroundColor:S.theme==='dark'?'#080810':'#f4f4f8'});
    const pdf=new jsPDF({orientation:'landscape',unit:'mm',format:'a4'});
    const w=pdf.internal.pageSize.getWidth();
    const h=canvas.height*w/canvas.width;
    pdf.addImage(canvas.toDataURL('image/png'),'PNG',0,0,w,h);
    pdf.save(`dashboard_${D.meta.ultimo_dia}.pdf`);
  }catch(e){alert('Error al exportar PDF: '+e.message);}
}

