// GESTIÓN DE MAPAS EDITABLES
// ════════════════════════════════════════════════════════════
const MAPAS_KEY = 'sk_mapas_override';

function loadMapasOverride(){
  try{ return JSON.parse(localStorage.getItem(MAPAS_KEY))||{}; }
  catch{ return {}; }
}
function saveMapasOverride(obj){ localStorage.setItem(MAPAS_KEY, JSON.stringify(obj)); }

// Devuelve los mapas efectivos (data.json + overrides del usuario)
function getMapas(){
  const base = D.mapas || {};
  const ov   = loadMapasOverride();
  return {
    ports:       {...(base.ports||{}),       ...(ov.ports||{})},
    activos:     {...(base.activos||{}),     ...(ov.activos||{})},
    monedas:     {...(base.monedas||{}),     ...(ov.monedas||{})},
    modalidades: {...(base.modalidades||{}), ...(ov.modalidades||{})},
    estados:     {...(base.estados||{}),     ...(ov.estados||{})},
    metodos:     {...(base.metodos||{}),     ...(ov.metodos||{})},
    tipo_reglas: ov.tipo_reglas || base.tipo_reglas || [],
    tipo_colores:{...(base.tipo_colores||{}), ...(ov.tipo_colores||{})},
    tipo_map:    {...(base.tipo_map||{}),    ...(ov.tipo_map||{})},
  };
}

// Renderiza un editor de mapa clave→valor dentro de un contenedor
function renderMapEditor(containerId, mapObj, keysReadonly=false){
  const cont = document.getElementById(containerId);
  if(!cont) return;
  cont.innerHTML = `<div class="map-hdr"><span>Código</span><span>Nombre legible</span><span></span></div>` +
    Object.entries(mapObj).map(([k,v])=>`
      <div class="map-row" data-container="${containerId}">
        <input class="key-input" value="${esc(k)}" placeholder="Código"
          ${keysReadonly?'readonly style="opacity:.6"':''}>
        <input class="val-input" value="${esc(v)}" placeholder="Nombre legible">
        <button class="map-del" onclick="this.closest('.map-row').remove()" title="Eliminar">×</button>
      </div>`).join('');
}

// Renderiza las reglas de clasificación
function renderReglasEditor(reglas){
  const cont = document.getElementById('map-reglas');
  if(!cont) return;
  const tipos = Object.keys((D.mapas?.tipo_colores)||TC);
  cont.innerHTML = `
    <div style="display:grid;grid-template-columns:1fr 1fr 1fr auto;gap:6px;
      font-size:9px;color:var(--tx3);text-transform:uppercase;letter-spacing:.6px;
      padding:0 0 4px;border-bottom:1px solid var(--bd);margin-bottom:4px">
      <span>Texto a buscar (separar con coma)</span>
      <span>Tipo resultado</span>
      <span>Orden</span>
      <span></span>
    </div>` +
    (reglas||[]).map((r,i)=>`
      <div class="regla-row" data-i="${i}">
        <input value="${esc((r.contiene||[]).join(', '))}" placeholder="TES, BONO, ...">
        <select style="font-size:11.5px;padding:5px 9px;border-radius:6px;background:var(--s2);color:var(--tx);border:1px solid var(--bd)">
          ${tipos.map(t=>`<option${t===r.tipo?' selected':''}>${esc(t)}</option>`).join('')}
          <option${r.tipo==='Otro'?' selected':''}>Otro</option>
        </select>
        <input type="number" value="${i+1}" min="1" style="width:60px;text-align:center">
        <button class="map-del" onclick="this.closest('.regla-row').remove()" title="Eliminar">×</button>
      </div>`).join('');
}

function addMapRow(containerId){
  const cont = document.getElementById(containerId);
  if(!cont) return;
  const row = document.createElement('div');
  row.className = 'map-row';
  row.dataset.container = containerId;
  row.innerHTML = `
    <input class="key-input" value="" placeholder="Código">
    <input class="val-input" value="" placeholder="Nombre legible">
    <button class="map-del" onclick="this.closest('.map-row').remove()" title="Eliminar">×</button>`;
  cont.appendChild(row);
  row.querySelector('.key-input').focus();
}

function addReglaRow(){
  const cont = document.getElementById('map-reglas');
  if(!cont) return;
  const tipos = Object.keys((D.mapas?.tipo_colores)||TC);
  const row = document.createElement('div');
  row.className = 'regla-row';
  row.innerHTML = `
    <input value="" placeholder="TES, BONO, ...">
    <select style="font-size:11.5px;padding:5px 9px;border-radius:6px;background:var(--s2);color:var(--tx);border:1px solid var(--bd)">
      ${tipos.map(t=>`<option>${esc(t)}</option>`).join('')}
      <option>Otro</option>
    </select>
    <input type="number" value="${cont.querySelectorAll('.regla-row').length+1}" min="1" style="width:60px;text-align:center">
    <button class="map-del" onclick="this.closest('.regla-row').remove()" title="Eliminar">×</button>`;
  cont.appendChild(row);
  row.querySelector('input').focus();
}

// Lee todos los editores y devuelve el objeto de mapas actualizado
function readMapasFromDOM(){
  const readMap = (containerId) => {
    const rows = document.querySelectorAll(`#${containerId} .map-row`);
    const obj = {};
    rows.forEach(row => {
      const k = row.querySelector('.key-input')?.value.trim();
      const v = row.querySelector('.val-input')?.value.trim();
      if(k && v) obj[k] = v;
    });
    return obj;
  };

  const reglas = [];
  document.querySelectorAll('#map-reglas .regla-row').forEach(row => {
    const inputs = row.querySelectorAll('input');
    const sel    = row.querySelector('select');
    const texto  = inputs[0]?.value.trim();
    const tipo   = sel?.value.trim();
    if(texto && tipo){
      reglas.push({
        contiene: texto.split(',').map(x=>x.trim()).filter(Boolean),
        tipo
      });
    }
  });

  return {
    ports:       readMap('map-ports'),
    activos:     readMap('map-activos'),
    monedas:     readMap('map-monedas'),
    modalidades: readMap('map-modalidades'),
    estados:     readMap('map-estados'),
    metodos:     readMap('map-metodos'),
    tipo_reglas: reglas,
  };
}

// Rellena el panel de mapas con los valores actuales
function renderPanelMapas(){
  const m = getMapas();
  renderMapEditor('map-ports',       m.ports);
  renderMapEditor('map-activos',     m.activos);
  renderMapEditor('map-monedas',     m.monedas);
  renderMapEditor('map-modalidades', m.modalidades);
  renderMapEditor('map-estados',     m.estados);
  renderMapEditor('map-metodos',     m.metodos);
  renderReglasEditor(m.tipo_reglas);
}

// Escapa HTML básico para atributos value
function esc(s){ return String(s).replace(/&/g,'&amp;').replace(/"/g,'&quot;').replace(/</g,'&lt;'); }

// Genera el bloque Python para pegar en CFG
function exportCfgPython(){
  const m = readMapasFromDOM();
  const ov = loadMapasOverride();
  const tipoMap = {...(D.mapas?.tipo_map||{}), ...(ov.tipo_map||{})};
  // Construir bloque Python
  const toDict = (obj, indent='        ') =>
    '{\n' + Object.entries(obj).map(([k,v])=>`${indent}"${k}": "${v}",`).join('\n') + `\n${indent.slice(4)}}`;
  const toList = (arr, indent='        ') =>
    '[\n' + arr.map(r=>`${indent}{"contiene": ${JSON.stringify(r.contiene)}, "tipo": "${r.tipo}"},`).join('\n') + `\n${indent.slice(4)}]`;

  const bloque = `
# ════ PEGAR ESTO EN CFG (procesar_datos.py) ════
    "ports":       ${toDict(m.ports)},
    "activos":     ${toDict(m.activos)},
    "monedas":     ${toDict(m.monedas)},
    "modalidades": ${toDict(m.modalidades)},
    "estados":     ${toDict(m.estados)},
    "metodos":     ${toDict(m.metodos)},
    "tipo_reglas": ${toList(m.tipo_reglas)},
    "tipo_map":    ${toDict(tipoMap)},
# ════════════════════════════════════════════════
`.trim();

  // Copiar al clipboard y mostrar
  navigator.clipboard?.writeText(bloque).catch(()=>{});
  const pre = document.createElement('pre');
  pre.style.cssText='background:var(--s2);padding:12px 14px;border-radius:8px;font-size:10px;overflow-x:auto;white-space:pre-wrap;margin-top:12px;border:1px solid var(--bd)';
  pre.textContent = bloque;
  const btn = document.querySelector('#fp-mapas button[onclick="exportCfgPython()"]');
  const existing = btn?.parentElement?.querySelector('pre');
  if(existing) existing.remove();
  btn?.insertAdjacentElement('afterend', pre);
}

// renderCfgRows y addCfgRow (usados desde el nuevo modal)
// Los tipos disponibles para clasificación
const TIPOS_BASE=['TES','Fondos','Liquidez','Derivados','AOR','TIDIS','CDT','Acciones','Titularizaciones','Otro'];
function getTiposDisponibles(){
  try{
    const custom=JSON.parse(localStorage.getItem('sk_tipos_custom')||'[]');
    return [...new Set([...TIPOS_BASE,...custom])];
  }catch{return TIPOS_BASE;}
}
function saveTipoCustom(nombre){
  nombre=nombre.trim();
  if(!nombre||TIPOS_BASE.includes(nombre))return false;
  const custom=JSON.parse(localStorage.getItem('sk_tipos_custom')||'[]');
  if(!custom.includes(nombre)){custom.push(nombre);localStorage.setItem('sk_tipos_custom',JSON.stringify(custom));}
  return true;
}
function removeTipoCustom(nombre){
  const custom=JSON.parse(localStorage.getItem('sk_tipos_custom')||'[]');
  localStorage.setItem('sk_tipos_custom',JSON.stringify(custom.filter(t=>t!==nombre)));
}
const TIPOS_DISPONIBLES=getTiposDisponibles; // función, no array — llamar con TIPOS_DISPONIBLES()

function _tipoSelect(selectedVal, dataAttr){
  var s='<select class="cfg-select" '+dataAttr+'>';
  getTiposDisponibles().forEach(function(t){
    s+='<option value="'+t+'"'+(t===selectedVal?' selected':'')+'>'+t+'</option>';
  });
  s+='</select>';
  return s;
}

function renderCfgRows(){
  const container=document.getElementById('cfgRows');
  const currentMap=loadCfg();
  // Mostrar: reglas manuales + especies clasificadas como Otro
  const others=D.tabla.filter(function(r){return r.tipo==='Otro'||currentMap[r.esp];}).map(function(r){return r.esp;});
  const allEsp=[...new Set([...Object.keys(currentMap),...others])];

  const cnt=document.getElementById('cfgRowsCount');
  if(cnt) cnt.textContent=allEsp.length+' reglas';

  if(allEsp.length===0){
    const otroCount=D.tabla.filter(function(r){return r.tipo==='Otro';}).length;
    container.innerHTML='<div style="font-size:12px;color:var(--tx2);padding:10px 0;line-height:1.8">'
      +(otroCount>0?'Hay <b style="color:var(--y)">'+otroCount+'</b> instrumentos sin clasificar.<br>Usa "Solo Otro" para verlos.':'Sin reglas configuradas.')+'</div>';
  } else {
    var html='';
    allEsp.forEach(function(esp){
      const currTipo=currentMap[esp]||D.tabla.find(function(r){return r.esp===esp;})?.tipo||'Otro';
      const safeId='cfgr-'+esp.replace(/[^a-zA-Z0-9]/g,'_').slice(0,30)+'_'+Math.abs(esp.split('').reduce(function(a,c){return a+c.charCodeAt(0);},0));
      const badge='<span class="bdg '+(BCL[currTipo]||'b-oth')+'">'+currTipo+'</span>';
      html+='<div class="cfg-row" id="'+safeId+'" style="align-items:center;border:1px solid var(--bd);border-radius:7px;padding:6px 8px;margin-bottom:4px;background:var(--s2)">';
      html+='<div style="min-width:0;flex:1"><div class="cfg-label" title="'+escAttr(esp)+'" style="font-size:11.5px;overflow:hidden;text-overflow:ellipsis">'+escHtml(esp.length>40?esp.slice(0,40)+'…':esp)+'</div>';
      html+='<div style="margin-top:2px">'+badge+'</div></div>';
      html+='<div style="display:flex;gap:6px;align-items:center;flex-shrink:0">';
      html+=_tipoSelect(currTipo,'data-esp="'+escAttr(esp)+'"');
      html+='<button onclick="removeCfgRow(\''+safeId+'\')" style="color:var(--r);font-size:16px;padding:2px 8px;flex-shrink:0;border:1px solid var(--bd);border-radius:5px" title="Eliminar regla">×</button>';
      html+='</div></div>';
    });
    container.innerHTML=html;
  }
}

function removeCfgRow(id){
  const el=document.getElementById(id);
  if(el){el.style.opacity='0';el.style.transition='opacity .2s';setTimeout(function(){el.remove();},200);}
}

// Búsqueda rápida de especie para agregar regla
function addCfgRow(){
  const container=document.getElementById('cfgRows');
  const id='cfgr_new_'+Date.now();

  // Crear fila con input de búsqueda + datalist
  const especies=[...new Set(D.tabla.map(function(r){return r.esp;}))].sort();
  const datalistId='dl_esp_'+Date.now();

  const el=document.createElement('div');
  el.className='cfg-row';
  el.id=id;
  el.style.cssText='align-items:center;border:2px dashed var(--g);border-radius:7px;padding:8px;margin-bottom:4px;background:var(--g4);animation:slideDown .2s ease';

  let optHtml='';
  especies.forEach(function(e){ optHtml+='<option value="'+escAttr(e)+'">'; });

  el.innerHTML='<input list="'+datalistId+'" class="cfg-input" placeholder="Buscar especie..." style="flex:1;font-size:12px" oninput="_cfgPreview(this)" autocomplete="off">'
    +'<datalist id="'+datalistId+'">'+optHtml+'</datalist>'
    +'<div style="display:flex;gap:6px;align-items:center;flex-shrink:0">'
    +_tipoSelect('CDT','data-tipo="1"')
    +'<button onclick="removeCfgRow(\''+id+'\')" style="color:var(--r);font-size:16px;padding:2px 8px;border:1px solid var(--bd);border-radius:5px">×</button>'
    +'</div>';

  container.appendChild(el);
  el.querySelector('input').focus();

  // Añadir datalist al documento
  const dl=document.createElement('datalist');
  dl.id=datalistId;
  especies.forEach(function(e){const o=document.createElement('option');o.value=e;dl.appendChild(o);});
  document.body.appendChild(dl);
}

function _cfgPreview(input){
  // Mostrar preview del tipo actual cuando se selecciona una especie conocida
  const esp=input.value.trim();
  const row=D.tabla.find(function(r){return r.esp===esp;});
  if(row){
    const hint=input.parentElement.querySelector('.cfg-hint-live');
    if(!hint){
      const h=document.createElement('div');
      h.className='cfg-hint-live';
      h.style.cssText='font-size:10px;color:var(--tx2);margin-top:2px';
      input.insertAdjacentElement('afterend',h);
    }
    const h2=input.parentElement.querySelector('.cfg-hint-live');
    if(h2) h2.textContent='Tipo actual: '+row.tipo+' — reasignar a:';
  }
}


// ─── FILTROS DEL PANEL DE CLASIFICACIÓN ───────────────────────
function _filterCfgRows(q){
  const input=document.getElementById('cfgEspSearch');
  if(input && q!==undefined) input.value=q;
  const term=(q||'').toLowerCase();
  const rows=document.querySelectorAll('#cfgRows [id^="cfgr"]');
  let visible=0;
  rows.forEach(function(row){
    const label=row.querySelector('.cfg-label');
    const txt=(label?label.title||label.textContent:'').toLowerCase();
    const show=!term||txt.includes(term);
    row.style.display=show?'':'none';
    if(show)visible++;
  });
  const cnt=document.getElementById('cfgRowsCount');
  if(cnt) cnt.textContent=visible+' '+( term?'encontrados':'reglas');
}

function _filterCfgByTipo(tipo){
  document.getElementById('cfgEspSearch').value='';
  const rows=document.querySelectorAll('#cfgRows [id^="cfgr"]');
  let visible=0;
  rows.forEach(function(row){
    const sel=row.querySelector('select[data-esp]');
    const currTipo=sel?sel.value:'';
    const show=currTipo===tipo;
    row.style.display=show?'':'none';
    if(show)visible++;
  });
  const cnt=document.getElementById('cfgRowsCount');
  if(cnt) cnt.textContent=visible+' de tipo '+tipo;
}

function _addTipoCustom(){
  const inp=document.getElementById('newTipoInput');
  if(!inp)return;
  const nombre=inp.value.trim();
  if(!nombre){inp.focus();return;}
  if(!saveTipoCustom(nombre)){
    inp.style.borderColor='var(--r)';
    setTimeout(()=>{inp.style.borderColor='';},1200);
    inp.placeholder='Ya existe o es un tipo base';
    return;
  }
  inp.value='';
  inp.placeholder='Ej: ETF, Inmobiliario, Infraestructura...';
  _renderCustomTipos();
  renderCfgRows(); // refrescar lista con nuevo tipo
}

function _renderCustomTipos(){
  const custom=JSON.parse(localStorage.getItem('sk_tipos_custom')||'[]');
  const list=document.getElementById('customTiposList');
  const badges=document.getElementById('customTiposBadges');
  if(list){
    list.innerHTML=custom.length===0
      ?'<span style="font-size:11px;color:var(--tx2)">Sin tipos personalizados aún.</span>'
      :custom.map(t=>`<span style="display:inline-flex;align-items:center;gap:5px;padding:4px 10px;border-radius:12px;background:var(--g3);border:1px solid rgba(0,133,74,.25);font-size:11px;font-weight:600;color:var(--g)">
        ${escHtml(t)}
        <button onclick="removeTipoCustom('${escAttr(t)}');_renderCustomTipos();renderCfgRows();" style="color:var(--r);font-size:13px;padding:0 2px;border:none;background:none;cursor:pointer;line-height:1" title="Eliminar">×</button>
      </span>`).join('');
  }
  if(badges){
    badges.innerHTML=custom.map(t=>`<span class="bdg b-oth" onclick="_filterCfgByTipo('${escAttr(t)}')" style="cursor:pointer">${escHtml(t)}</span>`).join('');
  }
}

function _showOnlyOtros(){
  // Mostrar todos los "Otro" del portafolio para reclasificar
  const currentMap=loadCfg();
  const otroEsps=[...new Set(D.tabla.filter(function(r){return r.tipo==='Otro';}).map(function(r){return r.esp;}))];
  const container=document.getElementById('cfgRows');
  // Añadir los que no están ya
  otroEsps.forEach(function(esp){
    const exists=[...container.querySelectorAll('[data-esp]')].some(function(s){return s.dataset.esp===esp;});
    if(!exists){
      const safeId='cfgr_o_'+esp.replace(/[^a-zA-Z0-9]/g,'_').slice(0,30)+'_'+Math.abs(esp.split('').reduce(function(a,c){return a+c.charCodeAt(0);},0));
      const el=document.createElement('div');
      el.id=safeId;
      el.style.cssText='display:flex;align-items:center;gap:8px;border:1px solid var(--bd);border-radius:7px;padding:6px 8px;margin-bottom:4px;background:var(--s2)';
      el.innerHTML='<div style="flex:1;font-size:11.5px;overflow:hidden;text-overflow:ellipsis" title="'+escAttr(esp)+'">'+escHtml(esp.length>40?esp.slice(0,40)+'…':esp)+'</div>'
        +'<div style="display:flex;gap:6px;align-items:center;flex-shrink:0">'
        +_tipoSelect('CDT','data-esp="'+escAttr(esp)+'"')
        +'<button onclick="removeCfgRow(\''+safeId+'\')" style="color:var(--r);font-size:16px;padding:2px 8px;border:1px solid var(--bd);border-radius:5px">×</button>'
        +'</div>';
      container.appendChild(el);
    }
  });
  // Filtrar para mostrar solo los "Otro"
  _filterCfgByTipo('Otro');
  const cnt=document.getElementById('cfgRowsCount');
  if(cnt) cnt.textContent=otroEsps.length+' sin clasificar';
}

// initAnalisis: eliminado — ver initRendimiento e initInstrumentos

// ════════════════════════════════════════════════════════════
// CONFIGURACIÓN MODAL MEJORADO
// ════════════════════════════════════════════════════════════
function setCfgTab(el){
  document.querySelectorAll('.modal-ftab').forEach(t=>t.classList.remove('on'));
  document.querySelectorAll('.modal-fpanel').forEach(p=>p.classList.remove('on'));
  el.classList.add('on');
  document.getElementById(el.dataset.fp).classList.add('on');
}

function openCfg(){
  renderCfgRows();
  _renderCustomTipos();
  renderPanelMapas();   // ← panel de mapas editables

  // Panel visual
  const u=UI_CFG;
  const _s=(id,val)=>{const el=document.getElementById(id);if(el)el.value=val;};
  const _c=(id,val)=>{const el=document.getElementById(id);if(el)el.checked=val;};
  _s('ui-theme',        S.theme);
  _s('ui-tabDefault',   u.tabDefault);
  _s('ui-insightsPos',  u.insightsPos);
  _s('ui-decimalPct',   String(u.decimalPct));
  _s('ui-tablePageSize',String(u.tablePageSize));
  _s('ui-exportFormat', u.exportFormat);
  _c('ui-chartAnim',    u.chartAnim);
  _c('ui-showNominal',  u.showNominal);
  _c('ui-compactKpis',  u.compactKpis);

  // Panel info
  const meta=D.meta||{};
  document.getElementById('cfgInfoMeta').innerHTML=[
    ['Organización',   meta.org||'—'],
    ['Último día',     meta.ultimo_dia||'—'],
    ['Primer día',     meta.primer_dia||'—'],
    ['Fechas totales', meta.n_fechas||'—'],
    ['Generado',       meta.generado||'—'],
  ].map(([l,v])=>`<div style="display:flex;justify-content:space-between;font-size:12px;
    padding:6px 10px;background:var(--s2);border-radius:6px">
    <span style="color:var(--tx2)">${l}</span>
    <span style="font-family:var(--mono);font-weight:600">${v}</span></div>`).join('');
  const dataUrl=meta.data_url||'';
  document.getElementById('cfgInfoData').innerHTML=
    dataUrl
      ? `Modo <b>remoto</b> — datos desde:<br><a href="${dataUrl}" target="_blank" style="color:var(--b);word-break:break-all">${dataUrl}</a>`
      : 'Modo <b>inline</b> — datos incrustados en el HTML.';
  document.getElementById('cfgOverlay').classList.add('on');
}

function closeCfg(){ document.getElementById('cfgOverlay').classList.remove('on'); }
function closeCfgOut(e){ if(e.target===document.getElementById('cfgOverlay')) closeCfg(); }

function saveCfgModal(){
  // 1. Mapa de reclasificación de especies (Tab "Tipos de activo")
  const newMap={};
  document.querySelectorAll('#cfgRows .cfg-row').forEach(row=>{
    const selects=row.querySelectorAll('select');
    let esp='',tipo='';
    if(selects.length===1){ esp=selects[0].dataset.esp; tipo=selects[0].value; }
    else if(selects.length===2){ esp=selects[0].value; tipo=selects[1].value; }
    if(esp&&tipo&&tipo!=='') newMap[esp]=tipo;
  });
  saveCfg(newMap);
  TIPO_MAP=newMap;

  // 2. Mapas editables (Tab "Portafolios & Mapas")
  const mapasNuevos = readMapasFromDOM();
  mapasNuevos.tipo_map = newMap;   // sincronizar con tab de tipos
  saveMapasOverride(mapasNuevos);

  // 3. Config UI (Tab "Visual")
  const _gv=(id,def='')=>{ const el=document.getElementById(id); return el?el.value:def; };
  const _gc2=(id)=>{ const el=document.getElementById(id); return el?el.checked:false; };
  const newUI={
    theme:         _gv('ui-theme','dark'),
    tabDefault:    _gv('ui-tabDefault','general'),
    insightsPos:   _gv('ui-insightsPos','top'),
    decimalPct:    parseInt(_gv('ui-decimalPct','2')),
    tablePageSize: parseInt(_gv('ui-tablePageSize','50')),
    exportFormat:  _gv('ui-exportFormat','csv'),
    chartAnim:     _gc2('ui-chartAnim'),
    showNominal:   _gc2('ui-showNominal'),
    compactKpis:   _gc2('ui-compactKpis'),
  };
  saveUICfg(newUI);
  UI_CFG=newUI;

  // Aplicar tema si cambió
  if(newUI.theme !== S.theme){
    S.theme=newUI.theme; applyTheme();
  }
  document.querySelectorAll('.kpi').forEach(el=>{
    el.style.padding=newUI.compactKpis?'10px 13px':'16px 18px';
  });

  closeCfg();
  // Reconstruir tab actual con los nuevos mapas
  Object.values(CH).forEach(c=>c&&c.destroy());
  Object.keys(CH).forEach(k=>delete CH[k]);
  Object.keys(S.init).forEach(k=>delete S.init[k]);
  initTab(S.tab);
}

function resetAllCfg(){
  if(!confirm('¿Restablecer toda la configuración al valor por defecto?')) return;
  localStorage.removeItem('sk_tipo_map');
  localStorage.removeItem('sk_ui_cfg');
  localStorage.removeItem('sk_mapas_override');
  TIPO_MAP=loadCfg(); UI_CFG=loadUICfg();
  closeCfg();
  location.reload();
}

function exportCfgJSON(){
  const data={tipo_map:TIPO_MAP,ui_cfg:UI_CFG};
  const b=new Blob([JSON.stringify(data,null,2)],{type:'application/json'});
  const a=document.createElement('a');a.href=URL.createObjectURL(b);
  a.download='dashboard_config.json';a.click();
}

// ════════════════════════════════════════════════════════════
// ATAJOS DE TECLADO
// ════════════════════════════════════════════════════════════
document.addEventListener('keydown',e=>{
  if(e.target.tagName==='INPUT'||e.target.tagName==='SELECT'||e.target.tagName==='TEXTAREA') return;
  const tabs=['resumen','composicion','evolucion','rendimiento','instrumentos','detalle','educacion'];
  if(e.key==='Escape'){ closeCfg(); return; }
  if(e.key.toLowerCase()==='t'){ toggleTheme(); return; }
  if(e.key.toLowerCase()==='c'){ openCfg(); return; }
  const n=parseInt(e.key);
  if(n>=1&&n<=7){
    const btn=document.querySelector(`.sb-item[data-t="${tabs[n-1]}"]`);
    if(btn) ST(btn);
  }
});

// ════════════════════════════════════════════════════════════
// INIT — despacha al init correcto según tab
// ════════════════════════════════════════════════════════════
function initTab(t){
  if(t==='resumen')      initResumen();
  if(t==='composicion')  initComposicion();
  if(t==='evolucion')    initEvolucion();
  if(t==='rendimiento')  initRendimiento();
  if(t==='instrumentos') initInstrumentos();
  if(t==='detalle')      initDetalle();
  // educacion: HTML estático, no necesita initTab
}

async function startApp(D_data){
  window.D=D_data;
  setLoad('Aplicando tema…', 85);

  // Aplicar config UI guardada (por defecto light)
  S.theme = UI_CFG.theme || localStorage.getItem('sk-theme') || 'light';
  applyTheme();

  setLoad('Inicializando filtros…', 90);
  document.getElementById('hdrFechaVal').textContent = D.meta.ultimo_dia;
  document.getElementById('hdrUpdVal').textContent   = D.meta.generado;
  initFilters();

  if(UI_CFG.insightsPos!=='none') initInsights();

  // Tab por defecto (nuevo nombre: resumen)
  const defaultTab = (UI_CFG.tabDefault||'resumen').replace('general','resumen');
  const defaultBtn = document.querySelector(`.sb-item[data-t="${defaultTab}"]`);
  const startTab   = defaultBtn ? defaultTab : 'resumen';
  const startBtn   = defaultBtn || document.querySelector('.sb-item[data-t="resumen"]');
  document.querySelectorAll('.sb-item').forEach(b=>b.classList.remove('on'));
  document.querySelectorAll('.page').forEach(p=>p.classList.remove('on'));
  if(startBtn) startBtn.classList.add('on');
  document.getElementById('pg-'+startTab)?.classList.add('on');
  _updateTopbar(startTab);
  S.tab=startTab;
  S.init[startTab]=true;
  setLoad('Renderizando…', 95);
  try{
    initTab(startTab);
  } catch(e){
    console.error('initTab error:',e);
    // No bloquear la carga aunque falle un tab
  }

  // Siempre ocultar el loading (aunque haya errores en el tab)
  setLoad('Listo', 100);
  const _ls=document.getElementById('loadScreen');
  if(_ls){ _ls.style.opacity='0'; _ls.style.transition='opacity .4s';
    setTimeout(()=>{_ls.remove();},450); }
}

window.addEventListener('DOMContentLoaded', async ()=>{
  const savedTheme=localStorage.getItem('sk-theme')||'light';
  document.documentElement.setAttribute('data-theme',savedTheme);

  // Siempre ocultar loading después de un máximo de 8 segundos
  const _failsafe=setTimeout(()=>{
    const ls=document.getElementById('loadScreen');
    if(ls){ ls.style.opacity='0'; ls.style.transition='opacity .4s';
      setTimeout(()=>ls.remove(),450); }
  }, 8000);

  try{
    setLoad('Cargando datos…', 20);
    const data = await loadData();
    if(!data) throw new Error('No se encontraron datos. Ejecuta procesar_datos.py primero.');
    setLoad('Datos listos', 80);
    clearTimeout(_failsafe);
    await startApp(data);
  } catch(e){
    clearTimeout(_failsafe);
    const msg=document.getElementById('loadMsg');
    const bar=document.getElementById('loadBar');
    if(msg) msg.textContent='Error: '+e.message;
    if(bar) bar.style.background='#ef4444';
    console.error('Dashboard error:',e);
    // Mostrar el error por 5 segundos y luego intentar mostrar la página igual
    setTimeout(()=>{
      const ls=document.getElementById('loadScreen');
      if(ls){ ls.style.opacity='0'; ls.style.transition='opacity .4s';
        setTimeout(()=>ls.remove(),450); }
    }, 5000);
  }
});
